      newDamage.id = i;
      newDamage.disp = (i == 0) ? true : false;
      newDamage.order = i + 1;
      for (let i = 0; i <= 3; ++i) {
        let newSupporter = JSON.parse(JSON.stringify(_this.fsSupporterProt));
        newSupporter.id = i;
        newSupporter.order = i + 1;
        newDamage.supporters.push(newSupporter);
      }
      _this.damageList.push(newDamage);
    }

    function mdown(e, targetNode) {
      preAction = "mdown";
      preActionTime = Date.now();
      preActionScrollY = window.scrollY;

      if (_this.sfModeEmphasis == 1) {
        // 部隊編成：強調表示On/Off切り替え
        if (targetNode.id.startsWith("sfnikke")) {
          setFsEmphasis(targetNode.lang);
        };

      } else {
        //クラス名に .dragTag を追加
        targetNode.classList.add("dragTag");
        // タッチデバイスとマウスのイベントの差異を吸収
        if(e.type === "mousedown") var event = e;
        else var event = e.changedTouches[0];
        
        // 要素内の相対座標を取得
        //dragX = event.pageX - targetNode.offsetLeft;
        //dragY = event.pageY - targetNode.offsetTop;
        dragX = targetNode.offsetLeft;
        dragY = targetNode.offsetTop;
        //dragX = 0
        //dragY = 0

        // 所属している要素のスクロール量を取得
        let parentElement = document.getElementById(targetNode.parentNode.id);
        let parent_rect = parentElement.getBoundingClientRect();
        scrollTop  = parent_rect.top;
        scrollLeft = parent_rect.left;
        //scrollTop  = parentElement.scrollTop;
        //scrollLeft = parentElement.scrollLeft;
        //scrollTop  = parent_rect.top + parentElement.scrollTop;
        //scrollLeft = parent_rect.left + parentElement.scrollLeft;

        // 要素内におけるクリック位置を計算
        let client_rect = targetNode.getBoundingClientRect();
        clickTop = event.pageY - (client_rect.top + window.pageYOffset);
        clickLeft = event.pageX - (client_rect.left + window.pageXOffset);

        // top要素のスクロール位置
        let topElement = undefined;
        if (_this.coSelTab == 3) topElement = document.getElementById("sfTop");
        if (_this.coSelTab == 4) topElement = document.getElementById("smTop");
        if (topElement == undefined) {
          topScrollY  = 0;
          topScrollX = 0;
        } else {
          topScrollY = topElement.scrollTop;
          topScrollX = topElement.scrollLeft;
        };

        // クリックまたはタップした時間
        downTime = performance.now();
      };
    };

    function mmove(e) {
      preAction = "mmove";
      preActionTime = Date.now();
      preActionScrollY = window.scrollY;
      // コンテキストメニュー非表示化
      if (_this.sfContextTarget != null) {
        document.getElementById('sfContextChar').style.display = "none";
        document.getElementById('sfContextSquad').style.display = "none";
        _this.sfContextTarget = null;
        _this.sfContextSquadSkillExists = false;
        _this.sfContextSquadRemoveExists = false;
      };
      // ツールチップが存在する場合はツールチップを削除
      removeToolTip();
      // フリックしたときに画面を動かさないようにデフォルト動作を抑制
      e.preventDefault();
      // ドラッグしている要素を取得
      let drag = document.getElementsByClassName("dragTag")[0];
      if (drag == undefined) return;
      // 同様にマウスとタッチの差異を吸収
      if(e.type === "mousemove") var event = e;
      else var event = e.changedTouches[0];

      // ドラック中にスクロールした場合のため現在のスクロール量を取得
      let topScrollYnow = 0;
      let topScrollXnow = 0;
      let topElement = undefined
      if (_this.coSelTab == 3) topElement = document.getElementById("sfTop");
      if (_this.coSelTab == 4) topElement = document.getElementById("smTop");
      if (topElement != undefined) {
        topScrollYnow = topElement.scrollTop - topScrollY;
        topScrollXnow = topElement.scrollLeft - topScrollX;
      };

      // マウスが動いた場所に要素を動かす
      drag.style.position = "absolute";
      drag.style.top = event.pageY + topScrollYnow - scrollTop - clickTop - window.scrollY + "px";
      drag.style.left = event.pageX + topScrollXnow - scrollLeft - clickLeft - window.scrollX + "px";

      //drag.style.top = event.pageY + topScrollYnow - scrollTop - clickTop + "px";
      //drag.style.left = event.pageX + topScrollXnow - scrollLeft - clickLeft + "px";

      //drag.style.top = event.pageY - scrollTop - dragY + "px";
      //drag.style.left = event.pageX - scrollLeft - dragX + "px";
      //drag.style.top = event.pageY - topScrollY - scrollTop - dragY + "px";
      //drag.style.left = event.pageX - topScrollX - scrollLeft - dragX + "px";
      //drag.style.top = e.clientY - topScrollY - scrollTop + "px";
      //drag.style.left = e.clientX - topScrollX - scrollLeft + "px";
      drag.style.zIndex = 999999;

      //if (_this.isTest == 1) {
      //  _this.testPa = drag.parentNode.id;
      //  _this.testA = event.pageY;
      //  _this.testB = topScrollYnow;
      //  _this.testC = scrollTop;
      //  _this.testD = clickTop;
      //  _this.testT = drag.style.top;
      //};
    };

    function mup(e) {
      preAction = "mup";
      preActionTime = Date.now();
      preActionScrollY = window.scrollY;

      // ツールチップが存在する場合はツールチップを削除
      //removeToolTip();

      let drag = document.getElementsByClassName("dragTag")[0];
      if (drag == undefined) return;

      // クラス名 .dragTagやtooltip も消す
      while (document.getElementsByClassName("dragTag")[0] != undefined) {
        let element = document.getElementsByClassName("dragTag")[0];
        element.classList.remove("dragTag");
      };

      //タッチデバイスとマウスのイベントの差異を吸収
      drag.style.display = "none";
      if (e.type == "mouseup" || e.type == "mouseleave") {
        var x = e.clientX;
        var y = e.clientY;
      } else {
        let t = e.changedTouches[0];
        var x = t.clientX;
        var y = t.clientY;
      }
      let dropPoint = document.elementFromPoint(x, y);
      drag.style.display = "";

      //ドロップ先にある要素による違いを吸収
      if (dropPoint == undefined) {
        var drop = undefined;
      } else if (dropPoint.id.includes("fsImgAttacker")) {
        var drop = dropPoint.parentNode.parentNode.parentNode;
      } else if (dropPoint.id.includes("fsImgSupporter")) {
        var drop = dropPoint.parentNode.parentNode.parentNode.parentNode;
      } else if (dropPoint.id.includes("fsMarkBurstAtk")) {
        var drop = dropPoint.parentNode.parentNode.parentNode.parentNode;
      } else if (dropPoint.id.includes("fsMarkBurstSup")) {
        var drop = dropPoint.parentNode.parentNode.parentNode.parentNode.parentNode;
      } else if (dropPoint.id.includes("fsMsgAttacker")) {
        var drop = dropPoint.parentNode;
      } else if (dropPoint.id.includes("fsMsgSupporter")) {
        var drop = dropPoint.parentNode;
      } else if (dropPoint.id.includes("mark")) {
        dropPoint = dropPoint.parentNode; var drop = dropPoint.parentNode;
      } else if (dropPoint.id.includes("sfMark")) {
        dropPoint = dropPoint.parentNode; var drop = dropPoint.parentNode;
      } else if (dropPoint.id.includes("sfName")) {
        dropPoint = dropPoint.parentNode.parentNode; var drop = dropPoint.parentNode;
      } else if (dropPoint.id.includes("nikke")) {
        var drop = dropPoint.parentNode;
      } else if (dropPoint.id.includes("mcKitPriority_")) {
        var drop = dropPoint;
      } else if (dropPoint.id.includes("mcBaseKitPriority_")) {
        var drop = dropPoint;
      } else if (dropPoint.id.includes("sfSquadField")) {
        var drop = undefined;
      } else {
        var drop = dropPoint;
      }

      if (drop == undefined) { // ドロップ先なし(画面外など)
        drag.style.position = "relative";
        drag.style.top = "0px";
        drag.style.left = "0px";
        drag.style.zIndex = 1;
      } else if (drop.id.includes("sfSquad")) { // ドロップ先が部隊1～6
        let idxTo = drop.childNodes.length; // ドロップ先の要素番号（デフォルトは最大値＝末尾）
        let idxFrom = 0; // ドロップ元の要素番号
        let cnt = 0;
        // ドロップ先の画像が部隊の枠の中の何番目の要素なのか探す
        drop.childNodes.forEach(function(item){
          if(item.id == dropPoint.id) idxTo = cnt;
          cnt++;
        });
        // ドロップ元と先が同一部隊内の場合、ドロップ元の要素番号を探す
        cnt = 0;
        if(drop.id == drag.parentNode.id) {
          drop.childNodes.forEach(function(item){
            if(item.id == drag.id) idxFrom = cnt;
            cnt++;
          });
          if(idxFrom < idxTo) { // ドロップ元要素番号<ドロップ先要素番号の場合、挿入先をドロップ先要素の後ろにする
            idxTo++;
          }
          if(performance.now() - downTime < 200) { //ドラック開始～終了が早すぎる場合は元の場所へ移動（ダブルクリックを考慮）
            idxTo = idxFrom;
          }
        };
        
        drop.insertBefore(drag, drop.childNodes.item(idxTo)); // ドロップ先画像を挿入
        drag.style.position = "relative";
        drag.style.top = "0px";
        drag.style.left = "0px";
        drag.style.zIndex = 1;

        if (drag.getAttribute("lang") === "クラスト") {
          for (let i=0; i<10; ++i) {
            let ran = Math.floor( Math.random() * 9);  // 0～8の乱数
            if (ran != _this.sfDispRandom) {
              _this.sfDispRandom = ran;
              i = 10;
            };
          };
          _this.nikkes.find(e => e.name === "クラスト").rand = _this.sfDispRandom;
        };

        _this.mSaveQf(_this.sqSquadSelect);

      } else if (drop.id.includes("Candidate")) { // ドロップ先が"候補一覧"
        let idx = 0;
        let cnt = 0;
        drop.childNodes.forEach(function(item){
          if(item.id != undefined && item.id.includes('nikke')) { // 四象限の場合は上下左右のコメントがあるのでnikke画像に限定
            if(item.id <= drag.id) idx = cnt+1;
            cnt++;
          }
        });
        drop.insertBefore(drag, drop.childNodes.item(idx));
        drag.style.position = "relative";
        drag.style.top = "0px";
        drag.style.left = "0px";
        drag.style.zIndex = 1;

        if (drop.id == "sfCandidate") _this.mSaveQf(_this.sqSquadSelect);

      } else if (drop.id == "smGraph") { // ドロップ先が"四象限グラフ"
        let dropRect = document.getElementById(drop.id).getBoundingClientRect(); // グラフの座標
        //let dragRect = document.getElementById(drag.id).getBoundingClientRect(); // ニケ画像の座標
        drop.appendChild(drag);
        drag.style.position = "absolute";
        //drag.style.top = y - dropRect.top - dragRect.height/2 + "px";
        //drag.style.left = x - dropRect.left - dragRect.width/2 + "px";
        drag.style.top = y - dropRect.top - clickTop - 2 + "px";
        drag.style.left = x - dropRect.left - clickLeft - 2 + "px";
        drag.style.zIndex = ++smZIndexCnt;

      } else if (drop.id.startsWith("mcKitPriority_") || drop.id.startsWith("mcBaseKitPriority_")) { // ドロップ先が"お手入れシミュのキット使用優先順マーク
        let dragSpl = drag.id.split("_");
        let dropSpl = drop.id.split("_");
        
        drag.style.position = "relative";
