    // ツールチップ関連
    function createTooltip(nikkeId, message, size) { // ツールチップ作成
      removeToolTip();
      tooltipElem = document.createElement('div');
      tooltipElem.innerHTML = message;
      tooltipElem.id = "tooltipX"
      tooltipElem.className = "tooltipX"
      tooltipElem.style.fontSize = size + "em";
      //tooltipElem.style.visibility = "visible";
      document.body.append(tooltipElem);
      tooltipNikkeId = nikkeId;
    };
    function setTop(buttonRect, tooltipRect) { // ツールチップ位置設定
      if (tooltipRect.height >= buttonRect.top) {
        tooltipElem.style.top = `${buttonRect.bottom}px`
        return buttonRect.bottom + tooltipRect.height;
      } else {
        tooltipElem.style.top = `${buttonRect.top - tooltipRect.height}px`
        return tooltipRect.height;
      }
    };
    function setLeft(buttonRect, buttonBaseDiff) {
      if (buttonRect.left + buttonBaseDiff < 0) {
        tooltipElem.style.left = "0px";
        return;
      }
      if (buttonRect.right - buttonBaseDiff > document.documentElement.clientWidth) {
        tooltipElem.style.right = "0px";
        return;
      }
      tooltipElem.style.left = `${buttonRect.left + buttonBaseDiff}px`;
    };
    function setTopHorizontal(buttonRect, tooltipRect, buttonBaseDiff) {
      if (buttonRect.top + buttonBaseDiff < 0) {
        tooltipElem.style.top = "0px";
        return;
      }
      if (buttonRect.bottom - buttonBaseDiff > document.documentElement.clientHeight) {
        tooltipElem.style.top = `${window.innerHeight - tooltipRect.height}px`;
        return;
      }
      tooltipElem.style.top = `${buttonRect.top + buttonBaseDiff}px`;
    };
    function setLeftHorizontal(buttonRect, tooltipRect) {
      if ((document.documentElement.clientWidth/2) > (buttonRect.left + buttonRect.width/2)) {
        tooltipElem.style.left = `${buttonRect.right}px`
        return buttonRect.right + tooltipRect.width;
      } else {
        tooltipElem.style.left = `${buttonRect.left - tooltipRect.width}px`
        return tooltipRect.width;
      }
    };
    function removeToolTip() { // ツールチップ消去
      let ret = false;
      if (tooltipElem) {
        let elements = document.getElementsByClassName("tooltipX");
        for (let i=0; i<elements.length; ++i) {
          elements[i].remove();
          ret = true;
        };
        tooltipElem = null;
      };
      tooltipNikkeId = "";
      return ret;
    };
    async function tooltipStart(target, flgTouch) { // ツールチップ開始
      if (_this.sfModeEmphasis == 1) return; // 強調設定モード中はツールチップを表示しない
      await wait(700);
      if (flgTouch == false && document.getElementsByClassName("dragTag")[0] != undefined) {
        tooltipNikkeId = "";
        return;
      };
      if (_this.coTouchDevice && tooltipDispTime > performance.now() - 500) {
        return;
      };
      if (target.id == tooltipNikkeId) {
        for (let i=80; i>=60; i-=5) {
          if (target.dataset.tooltip != undefined) {
            if (window.innerWidth > 520) { // 画面横幅520px以上
              createTooltip(target.id, target.dataset.tooltip, i/100);
              const buttonRect = target.getBoundingClientRect();
              const tooltipRect = tooltipElem.getBoundingClientRect();
              if (document.documentElement.clientHeight > document.documentElement.clientWidth) {
                const buttonBaseDiff = (buttonRect.width - tooltipRect.width) / 2;
                let height = setTop(buttonRect, tooltipRect);
                setLeft(buttonRect, buttonBaseDiff);
                if (height < window.innerHeight) {
                  break;
                };
              } else {
                const buttonBaseDiff = (buttonRect.height - tooltipRect.height) / 2;
                let width = setLeftHorizontal(buttonRect, tooltipRect);
                setTopHorizontal(buttonRect, tooltipRect, buttonBaseDiff);
                if (width < window.innerWidth) {
                  break;
                };
              };
            } else { // 画面横幅520px以下
              createTooltip(target.id, target.dataset.tooltip, i/100);
              const tooltipRect = tooltipElem.getBoundingClientRect();
              let top = window.innerHeight/2 - tooltipRect.height/2;
              let left = window.innerWidth/2 - tooltipRect.width/2;
              if (top >= 0 && left >= 0) {
                tooltipElem.style.top = `${top}px`
                tooltipElem.style.left = `${left}px`;
                break;
              };
            };
          };
        };
      };
      tooltipDispTime = performance.now(); // ツールチップ表示開始時間
    };
