    mAlMatchNikkeCheck(nikke) { // アリーナ：対戦表の対象キャラ選択
      let _this = this;
      let matchSetSelectIdx = -1;   // 選択している対戦表セットのindex

      // 選択している対戦表セットのindexを取得
      for(let i=0; i<_this.alMatchSet.length; ++i) {
        if (_this.alMatchSet[i]) matchSetSelectIdx = i;
      };
      
      // 5キャラ以上選択しようとした場合は何もしない
      if (_this.alMatchList[matchSetSelectIdx].nikkes[_this.alMatchSelectIdx].length >= 5 && nikke.check == false) return;

      // 選択状態を反転
      //nikke.check = !nikke.check;

      // 選択キャラ欄へ追加または削除
      if (_this.alMatchList[matchSetSelectIdx].nikkes[_this.alMatchSelectIdx].find(e => e.orgid === nikke.orgid) === undefined) {
        let nikkeData = _this.nikkes.find(e => e.orgid === nikke.orgid);
        if (nikkeData != undefined) {
          let newNikke = JSON.parse(JSON.stringify(nikkeData));
          if (_this.alMatchList[matchSetSelectIdx].nikkes[_this.alMatchSelectIdx].length == 0) {
            newNikke.alMatchMain = 1;   // 部隊最初の1人の場合はメインとして登録
          } else {
            newNikke.alMatchMain = 0;
          };
          newNikke.alMatchMode = 1;     // 計算対象として登録
          newNikke.alPowerBandIdx = 0;
          _this.alMatchList[matchSetSelectIdx].nikkes[_this.alMatchSelectIdx].push(newNikke);
        };
      } else {
        _this.alMatchList[matchSetSelectIdx].nikkes[_this.alMatchSelectIdx] = _this.alMatchList[matchSetSelectIdx].nikkes[_this.alMatchSelectIdx].filter(e => e.orgid !== nikke.orgid);
      };

      // 対戦表再計算
      _this.mAlMatchMainFlow(_this.alMatchList[matchSetSelectIdx]);
    },

