    mAlMatchCandidateCandi() {  // アリーナ：対戦表の部隊候補強調
      let _this = this;
      //let matchSetSelectIdx = -1;   // 選択している対戦表セットのindex

      // 選択している対戦表セットのindexを取得
      //for(let i=0; i<_this.alMatchSet.length; ++i) {
      //  if (_this.alMatchSet[i]) matchSetSelectIdx = i;
      //};

      // 戦闘履歴で同一部隊だったキャラにフラグを立てる
      /*if (_this.alMatchCandidateCandi == 1 && _this.alMatchList[matchSetSelectIdx].nikkes[_this.alMatchSelectIdx].length >= 1) {
        _this.alMatchCandidate.forEach(function(nikke){
          if (_this.alMatchList[matchSetSelectIdx].nikkesAll[_this.alMatchSelectIdx].find(e => e.orgid === nikke.orgid) != undefined) {
            nikke.candidate = true;
          } else {
            nikke.candidate = false;
