        });
      } else {
        _this.alMatchCandidate.forEach(function(nikke){
          nikke.candidate = true;
        });
      };*/

      if (_this.alMatchCandidateCandi == 1) {
        _this.alMatchCandidate.forEach(function(nikke){
          nikke.candidate = true;

          // 現在選択中の部隊を除き、他部隊で使用されているキャラはフラグを落とす
          for(let i=0; i<_this.alMatchList.length; ++i) {
            if (_this.alMatchSet[i] == false) {
              if (_this.alMatchList[i].nikkes[_this.alMatchSelectIdx].find(e => e.orgid === nikke.orgid) != undefined) {
                nikke.candidate = false;
              };
            };
          };
          
        });
      } else {
        _this.alMatchCandidate.forEach(function(nikke){
          nikke.candidate = true;
        });
      };
    },

    mAlMatchWinPridictChange(matchIdx, newVal) { // アリーナ：個人戦績表示On/Off設定
      let _this = this;
      _this.alMatchWinPredict[matchIdx] = newVal;
