    mAlMatchMainFlow(match) { // アリーナ：対戦表メインフロー
      let _this = this;

      // 選択候補一覧のチェック状態を一旦外す
      _this.alMatchCandidate.forEach(function(nikke){
        nikke.check = false;
      });

      // 選択候補一覧にて部隊設定キャラをチェック状態にする
      _this.alMatchCandidate.forEach(function(nikke){
        if (match.nikkes[_this.alMatchSelectIdx].find(e => e.orgid === nikke.orgid) != undefined) {
          nikke.check = true;
        };
      });

      // 現在の部隊で5人選択済みの場合は他をグレーアウト
      if (match.nikkes[_this.alMatchSelectIdx].length >= 5) {
        _this.alMatchChackFlg = true;  // グレーアウト
      } else {
        _this.alMatchChackFlg = false;
      };

      // 再計算
      _this.mAlMatchItemCalc(match);
      
      // 部隊候補強調
      _this.mAlMatchCandidateCandi();
      
      _this.$set(_this.alMatchList, 0, _this.alMatchList[0]);

      // ローカルストレージへ設定を保存
      let nikkeOrgidList = [];
      match.nikkes[_this.alMatchSelectIdx].forEach(function(nikke){
        nikkeOrgidList.push(nikke.orgid);
      });
      localStorage.setItem('alMatch_' + match.idx + '_' + _this.alMatchSelectIdx + "_nikkes", nikkeOrgidList.join(","));
    },

