    mAlCandidateSort(candidate) { // アリーナ：選択候補ソート
      let _this = this;
      candidate.forEach(function(nikke){
        nikke.allSort = "";
        if (_this.alCandidateSort == 1) {
          nikke.allSort += String(1000 - nikke.useRate*10).padStart(4, "0");
        };
        nikke.allSort += String(nikke.burstclassSort).padStart(3, "0");
        nikke.allSort += String(nikke.elementalSort).padStart(3, "0");
        nikke.allSort += String(10000 - nikke.implementation).padStart(3, "0");
      });
      candidate.sort((a,b) => {
        if (a.allSort > b.allSort) { return 1 }
        if (a.allSort < b.allSort) { return -1 }
      });
    },

    mAlPartySort() { // アリーナ：部隊戦績ソート
      let _this = this;

      // 使用率（次点戦闘数、勝率）ソート
      if (_this.alTeamSort == 1) {
        _this.alPartyList[_this.alPartySelect].resultListParty.sort((a,b) => {
          if (parseFloat(a.useRate) > parseFloat(b.useRate)) { return -1 }
          if (parseFloat(a.useRate) < parseFloat(b.useRate)) { return 1 }
          if (parseFloat(a.useRate) == parseFloat(b.useRate)) {
            if (a.buttleNum > b.buttleNum) { return -1 }
            if (a.buttleNum < b.buttleNum) { return 1 }
            if (a.buttleNum == b.buttleNum) {
              if (parseFloat(a.winRate) > parseFloat(b.winRate)) { return -1 }
              if (parseFloat(a.winRate) < parseFloat(b.winRate)) { return 1 }
            }
          }
        });
      
      // 戦闘数（次点使用率、勝率）ソート
      } else if (_this.alTeamSort == 2) {
        _this.alPartyList[_this.alPartySelect].resultListParty.sort((a,b) => {
          if (a.buttleNum > b.buttleNum) { return -1 }
          if (a.buttleNum < b.buttleNum) { return 1 }
          if (a.buttleNum == b.buttleNum) {
            if (parseFloat(a.useRate) > parseFloat(b.useRate)) { return -1 }
            if (parseFloat(a.useRate) < parseFloat(b.useRate)) { return 1 }
            if (parseFloat(a.useRate) == parseFloat(b.useRate)) {
              if (parseFloat(a.winRate) > parseFloat(b.winRate)) { return -1 }
              if (parseFloat(a.winRate) < parseFloat(b.winRate)) { return 1 }
            }
          }
        });
      
      // 勝率（次点使用率、戦闘数）ソート
      } else if (_this.alTeamSort == 3) {
        _this.alPartyList[_this.alPartySelect].resultListParty.sort((a,b) => {
          if (parseFloat(a.winRate) > parseFloat(b.winRate)) { return -1 }
          if (parseFloat(a.winRate) < parseFloat(b.winRate)) { return 1 }
          if (parseFloat(a.winRate) == parseFloat(b.winRate)) {
            if (parseFloat(a.useRate) > parseFloat(b.useRate)) { return -1 }
            if (parseFloat(a.useRate) < parseFloat(b.useRate)) { return 1 }
            if (parseFloat(a.useRate) == parseFloat(b.useRate)) {
              if (a.buttleNum > b.buttleNum) { return -1 }
              if (a.buttleNum < b.buttleNum) { return 1 }
            }
          }
        });
      
      // 勝率×戦闘数ソート
      } else if (_this.alTeamSort == 4) {
        _this.alPartyList[_this.alPartySelect].resultListParty.sort((a,b) => {
          if (parseFloat(a.winRate) * a.buttleNum > parseFloat(b.winRate) * b.buttleNum) { return -1 }
          if (parseFloat(a.winRate) * a.buttleNum < parseFloat(b.winRate) * b.buttleNum) { return 1 }
        });

      // バースト速度ソート
      } else {
        _this.alPartyList[_this.alPartySelect].resultListParty.sort((a,b) => {
          if (a.burstSpeedStep > b.burstSpeedStep) { return 1 }
          if (a.burstSpeedStep < b.burstSpeedStep) { return -1 }
          if (a.burstSpeedStep == b.burstSpeedStep) {
            if (parseFloat(a.burstGauge) > parseFloat(b.burstGauge)) { return -1 }
            if (parseFloat(a.burstGauge) < parseFloat(b.burstGauge)) { return 1 }
            if (parseFloat(a.burstGauge) == parseFloat(b.burstGauge)) {
              if (parseFloat(a.useRate) > parseFloat(b.useRate)) { return -1 }
              if (parseFloat(a.useRate) < parseFloat(b.useRate)) { return 1 }
            }
          }
        });
      };
    },

