      if (nikke == undefined) return;

      // 5キャラ以上選択しようとした場合は何もしない
      if (targetPartyList.nikkesOwn.length >= 5 && nikke.check == false) return;

      // 選択状態を反転
      nikke.check = !nikke.check;

      // 選択キャラ欄へ追加または削除
      if (targetPartyList.nikkesOwn.find(e => e.name === nikke.name) === undefined) {
        let nikkeData = _this.nikkes.find(e => e.name === nikke.name);
        if (nikkeData != undefined) {
          let newNikke = JSON.parse(JSON.stringify(nikkeData));
          targetPartyList.nikkesOwn.push(newNikke);
        };
      } else {
        targetPartyList.nikkesOwn = targetPartyList.nikkesOwn.filter(e => e.name !== nikke.name);
      };

      // メインフロー
      _this.mAlMainFlow(_this.alPartySelect);
    },

