          _this.mSsChangeSkillLvSub_NeedDay(idxEd); // 所要日数計算（スキルⅠ～Ⅲ、バーストⅠ～Ⅲ）
        };
      };

      // カスタムパックⅩⅠ（選択枠2）
      if(_this.ssPackItems[9].BuyNum[0] >= 1) {
        for(let k=1; k<=_this.ssPackItems[9].BuyNum[0]; ++k) {
          maxDay = Math.max(_this.ssSkill[idxEd].NeedDay[0], _this.ssSkill[idxEd].NeedDay[1], _this.ssSkill[idxEd].NeedDay[3], _this.ssSkill[idxEd].NeedDay[4]);
          if     (maxDay == _this.ssSkill[idxEd].NeedDay[0]) idxBuy = 0;
          else if(maxDay == _this.ssSkill[idxEd].NeedDay[1]) idxBuy = 1;
          else if(maxDay == _this.ssSkill[idxEd].NeedDay[3]) idxBuy = 3;
          else                                               idxBuy = 4;
          _this.ssPackItems[idxBuy].GetNum[0] += _this.ssPackItemNums[9].Num2[idxBuy];
          _this.ssPackItems[9].GetManual[idxBuy]++;
          _this.mSsChangeSkillLvSub_NeedQty(idxEd); // 必要量計算（スキルⅠ～Ⅲ、バーストⅠ～Ⅲ）
          _this.mSsChangeSkillLvSub_NeedDay(idxEd); // 所要日数計算（スキルⅠ～Ⅲ、バーストⅠ～Ⅲ）
        };
      };

      // カスタムパックⅩⅠ（選択枠1）
      if(_this.ssPackItems[9].BuyNum[0] >= 1) {
        for(let k=1; k<=_this.ssPackItems[9].BuyNum[0]; ++k) {
          maxDay = Math.max(_this.ssSkill[idxEd].NeedDay[0], _this.ssSkill[idxEd].NeedDay[1], _this.ssSkill[idxEd].NeedDay[3], _this.ssSkill[idxEd].NeedDay[4]);
          if     (maxDay == _this.ssSkill[idxEd].NeedDay[0]) idxBuy = 0;
          else if(maxDay == _this.ssSkill[idxEd].NeedDay[1]) idxBuy = 1;
          else if(maxDay == _this.ssSkill[idxEd].NeedDay[3]) idxBuy = 3;
          else                                               idxBuy = 4;
          _this.ssPackItems[idxBuy].GetNum[0] += _this.ssPackItemNums[9].Num1[idxBuy];
          _this.ssPackItems[9].GetManual[idxBuy]++;
          _this.mSsChangeSkillLvSub_NeedQty(idxEd); // 必要量計算（スキルⅠ～Ⅲ、バーストⅠ～Ⅲ）
          _this.mSsChangeSkillLvSub_NeedDay(idxEd); // 所要日数計算（スキルⅠ～Ⅲ、バーストⅠ～Ⅲ）
        };
      };

      // 30-DAY成長補給箱
      if(_this.ssPackItems[15].BuyNum[0] >= 1) {
        for(let k=1; k<=_this.ssPackItems[15].BuyNum[0]; ++k) {
          maxDay = Math.max(_this.ssSkill[idxEd].NeedDay[0], _this.ssSkill[idxEd].NeedDay[1], _this.ssSkill[idxEd].NeedDay[2], _this.ssSkill[idxEd].NeedDay[3], _this.ssSkill[idxEd].NeedDay[4], _this.ssSkill[idxEd].NeedDay[5]);
          if     (maxDay == _this.ssSkill[idxEd].NeedDay[0]) idxBuy = 0;
          else if(maxDay == _this.ssSkill[idxEd].NeedDay[1]) idxBuy = 1;
          else if(maxDay == _this.ssSkill[idxEd].NeedDay[2]) idxBuy = 2;
          else if(maxDay == _this.ssSkill[idxEd].NeedDay[3]) idxBuy = 3;
          else if(maxDay == _this.ssSkill[idxEd].NeedDay[4]) idxBuy = 4;
          else                                               idxBuy = 5;
          _this.ssPackItems[idxBuy].GetNum[0] += _this.ssPackItemNums[15].Num1[idxBuy];
          _this.ssPackItems[15].GetManual[idxBuy]++;
          _this.mSsChangeSkillLvSub_NeedQty(idxEd); // 必要量計算（スキルⅠ～Ⅲ、バーストⅠ～Ⅲ）
          _this.mSsChangeSkillLvSub_NeedDay(idxEd); // 所要日数計算（スキルⅠ～Ⅲ、バーストⅠ～Ⅲ）
        };
      }

      // スキルマニュアル選択ボックス
      for (let i=0; i<=3; ++i) {
        if(_this.ssPackItems[7].BuyNum[i] >= 1) {
          for(let k=1; k<=_this.ssPackItems[7].BuyNum[i]; ++k) {
            maxDay = Math.max(_this.ssSkill[idxEd].NeedDay[0], _this.ssSkill[idxEd].NeedDay[1], _this.ssSkill[idxEd].NeedDay[2]);
            if     (maxDay == _this.ssSkill[idxEd].NeedDay[0]) idxBuy = 0;
            else if(maxDay == _this.ssSkill[idxEd].NeedDay[1]) idxBuy = 1;
            else                                               idxBuy = 2;
            _this.ssPackItems[idxBuy].GetNum[i] += _this.ssPackItemNums[7].Num1[idxBuy];
            _this.ssPackItems[7].GetManual[idxBuy]++;
            _this.mSsChangeSkillLvSub_NeedQty(idxEd); // 必要量計算（スキルⅠ～Ⅲ、バーストⅠ～Ⅲ）
            _this.mSsChangeSkillLvSub_NeedDay(idxEd); // 所要日数計算（スキルⅠ～Ⅲ、バーストⅠ～Ⅲ）
          };
        };
      };

      // バーストマニュアル選択ボックス
      for (let i=0; i<=3; ++i) {
        if(_this.ssPackItems[8].BuyNum[i] >= 1) {
          for(let k=1; k<=_this.ssPackItems[8].BuyNum[i]; ++k) {
            maxDay = Math.max(_this.ssSkill[idxEd].NeedDay[3], _this.ssSkill[idxEd].NeedDay[4], _this.ssSkill[idxEd].NeedDay[5]);
            if     (maxDay == _this.ssSkill[idxEd].NeedDay[3]) idxBuy = 3;
            else if(maxDay == _this.ssSkill[idxEd].NeedDay[4]) idxBuy = 4;
            else                                               idxBuy = 5;
            _this.ssPackItems[idxBuy].GetNum[i] += _this.ssPackItemNums[8].Num1[idxBuy];
            _this.ssPackItems[8].GetManual[idxBuy]++;
            _this.mSsChangeSkillLvSub_NeedQty(idxEd); // 必要量計算（スキルⅠ～Ⅲ、バーストⅠ～Ⅲ）
            _this.mSsChangeSkillLvSub_NeedDay(idxEd); // 所要日数計算（スキルⅠ～Ⅲ、バーストⅠ～Ⅲ）
          };
        };
      };

      // 必要量再計算
      _this.mSsChangeSkillLvSub_NeedQty(idxEd);

      // 所要日数再計算（スキルⅠ～Ⅲ、バーストⅠ～Ⅲ）
      _this.mSsChangeSkillLvSub_NeedDay(idxEd);

      // 属性コード、所要日数など
      for(let j=0; j<=idxEd; ++j) {
        // 必要量計算（属性コード）
        _this.ssSkill[j].NeedQty[6] = _this.ssSlillNeeds[_this.ssSkill[j].Goal[0]].Value[3]
                            - _this.ssSlillNeeds[_this.ssSkill[j].Now[0]].Value[3]
                            + _this.ssSlillNeeds[_this.ssSkill[j].Goal[1]].Value[3]
                            - _this.ssSlillNeeds[_this.ssSkill[j].Now[1]].Value[3]
                            + _this.ssSlillNeeds[_this.ssSkill[j].Goal[2]].Value[7]
                            - _this.ssSlillNeeds[_this.ssSkill[j].Now[2]].Value[7];
        if(j>=1) _this.ssSkill[j].NeedQty[6] += _this.ssSkill[j-1].NeedQty[6];
        _this.ssSkill[j].DispQty[6] = _this.ssSkill[j].NeedQty[6];
        if(_this.ssSkill[j].DispQty[6] < 0) _this.ssSkill[j].DispQty[6] = 0;

        // 所要日数（属性コード）
        _this.ssSkill[j].NeedDay[6] = 0; // ドロップがランダムなので計算の対象外

        // 最大所要日数（属性コード以外）
        maxDay = Math.max(_this.ssSkill[j].NeedDay[0]
                            ,_this.ssSkill[j].NeedDay[1]
                            ,_this.ssSkill[j].NeedDay[2]
                            ,_this.ssSkill[j].NeedDay[3]
                            ,_this.ssSkill[j].NeedDay[4]
                            ,_this.ssSkill[j].NeedDay[5]);

        // 所要日数グラフ（属性コード以外）
        for(let i=0; i<=5; ++i) {
          _this.ssSkill[j].NeedDayPar[i] = Math.floor(_this.ssSkill[j].NeedDay[i] / (maxDay*1.2) * 100);
        };

        // 到達予想日（属性コード以外）
        let today = new Date();
        if (isNaN(maxDay)) {
          _this.ssSkill[j].ArrivalDate = "到達不可";
        } else {
          today.setDate(today.getDate() + maxDay);
          _this.ssSkill[j].ArrivalDate = (today.getFullYear()+"").slice(-2) + "/" + ("00"+(today.getMonth()+1)).slice(-2) + "/" + ("00"+today.getDate()).slice(-2) + "<br>(" + [ "日", "月", "火", "水", "木", "金", "土" ][today.getDay()] + ")";
        };
      };

      // 現在日時
      _this.ssToday = new Date();
      _this.ssToday = "現在：" + (this.ssToday.getFullYear()+"").slice(-2) + "/" + ("00"+(this.ssToday.getMonth()+1)).slice(-2) + "/" + ("00"+this.ssToday.getDate()).slice(-2) + "(" + [ "日", "月", "火", "水", "木", "金", "土" ][this.ssToday.getDay()] + ")";

      // スキルバーの現在と目標が逆転した時の調整
      for(let j=0; j<=idxEd; ++j) {
        for(let i=0; i<_this.ssSkill[j].Now.length; ++i) {
          if (Number(_this.ssSkill[j].Now[i]) <= Number(_this.ssSkill[j].Goal[i])) {
            _this.ssSkill[j].ZIndexBar[i*2 + 0] = 1;
            _this.ssSkill[j].ZIndexBar[i*2 + 1] = 0;
          } else {
            _this.ssSkill[j].ZIndexBar[i*2 + 0] = 0;
            _this.ssSkill[j].ZIndexBar[i*2 + 1] = 1;
          }
        };
      };

      // 画面へ値反映するための処理
      for(let j=0; j<idxEd; ++j) {
        for(let i=0; i<_this.ssSkill[j].Now.length; ++i) {
          _this.$set(_this.ssSkill[j].Now, i, _this.ssSkill[j].Now[i]);
        }
        for(let i=0; i<_this.ssSkill[j].Goal.length; ++i) {
          _this.$set(_this.ssSkill[j].Goal, i, _this.ssSkill[j].Goal[i]);
        }
        for(let i=0; i<_this.ssSkill[j].ZIndexBar.length; ++i) {
          _this.$set(_this.ssSkill[j].ZIndexBar, i, _this.ssSkill[j].ZIndexBar[i]);
        }
        for(let i=0; i<_this.ssSkill[j].DispQty.length; ++i) {
          _this.$set(_this.ssSkill[j].DispQty, i, _this.ssSkill[j].DispQty[i]);
        }
        for(let i=0; i<_this.ssSkill[j].NeedQty.length; ++i) {
          _this.$set(_this.ssSkill[j].NeedQty, i, _this.ssSkill[j].NeedQty[i]);
        }
        for(let i=0; i<_this.ssSkill[j].NeedDay.length; ++i) {
          _this.$set(_this.ssSkill[j].NeedDay, i, _this.ssSkill[j].NeedDay[i]);
        }
      };

      _this.mSsSetSkillInfo(idx); // スキル詳細設定
      _this.mSsChangeSkillPage(idx, page);
    },

    mSsChangeSkillLvSub_NeedQty(idxEd) { // スキル：スキルレベル変更（必要量計算）
      let _this = this;
      for(let j=0; j<=idxEd; ++j) {
        // スキルⅠ～Ⅲ
        for(let i=0; i<=2; ++i) {
          _this.ssSkill[j].NeedQty[i] = _this.ssSlillNeeds[_this.ssSkill[j].Goal[0]].Value[i]
                                      - _this.ssSlillNeeds[_this.ssSkill[j].Now[0]].Value[i]
                                      + _this.ssSlillNeeds[_this.ssSkill[j].Goal[1]].Value[i]
                                      - _this.ssSlillNeeds[_this.ssSkill[j].Now[1]].Value[i]
                                      - _this.ssPosSkill[i];
          if(j==0) _this.ssSkill[j].NeedQty[i] -= _this.ssPackItems[i].GetNum[0]; // 課金アイテム分を引く
          if(j>=1) _this.ssSkill[j].NeedQty[i] += _this.ssSkill[j-1].NeedQty[i]; // 前キャラの必要量を加える
          _this.ssSkill[j].DispQty[i] = _this.ssSkill[j].NeedQty[i];
          if(_this.ssSkill[j].DispQty[i] < 0) _this.ssSkill[j].DispQty[i] = 0;
        };

        // バーストⅠ～Ⅲ
        for(let i=3; i<=5; ++i) {
          _this.ssSkill[j].NeedQty[i] = _this.ssSlillNeeds[_this.ssSkill[j].Goal[2]].Value[i+1]
                                      - _this.ssSlillNeeds[_this.ssSkill[j].Now[2]].Value[i+1]
                                      - _this.ssPosBurst[i-3];
          if(j==0) _this.ssSkill[j].NeedQty[i] -= _this.ssPackItems[i].GetNum[0]; // 課金アイテム分を引く                                    
          if(j>=1) _this.ssSkill[j].NeedQty[i] += _this.ssSkill[j-1].NeedQty[i]; // 前キャラの必要量を加える
          _this.ssSkill[j].DispQty[i] = _this.ssSkill[j].NeedQty[i];
          if(_this.ssSkill[j].DispQty[i] < 0) _this.ssSkill[j].DispQty[i] = 0;
        };
      };
    },

    mSsChangeSkillLvSub_NeedDay(idxEd) { // スキル：スキルレベル変更（所要日数計算）
      let _this = this;

      for(let j=0; j<=idxEd; ++j) {

        // スキルⅠ～Ⅲ(i=0,1,2)、バーストⅠ～Ⅲ(i=3,4,5)
        for(let i=0; i<=5; ++i) {
          let rem = _this.ssSkill[j].NeedQty[i];  // 必要数の残り
          let days = 0;
          let today = new Date();
          let baseday = new Date();
          baseday.setFullYear(2024, 3, 25);
          while(rem > 0) {
            days++;
            today.setDate(today.getDate() + 1);

            // 毎日
            rem -= _this.ssPackItems[i].GetNum[1];  // 課金パック分
            if(_this.ssSimuDegree >= 14) {
              rem -= _this.ssSimu[14].Value[i]; // シミュレーションルーム5-Cクリア報酬
            } else if(_this.ssSimu[_this.ssSimuDegree].Value[i] > 0) {
              rem -= _this.ssSimu[_this.ssSimuDegree].Value[i]; // シミュレーションルーム1-A～5-Bクリア報酬
            };

            // 毎週火曜
            if (today.getDay() == 2) {
              rem -= _this.ssPackItems[i].GetNum[2];  // 課金パック分
              // 2週に1回、シミュOCが1段階以上クリア
              if(((today-baseday)/86400000 % 14) == 12 && _this.ssSimuDegree >= 15) {
                rem -= _this.ssSimu[_this.ssSimuDegree].Value[i]; // OC1以上クリア
              };
            };

            // 毎月1日
            if (today.getDate() == 1) {
              rem -= _this.ssPackItems[i].GetNum[3];  // 課金パック分
            };

            if (days >= 32 && rem == _this.ssSkill[j].NeedQty[i]) {
              days = "到達不可";
              rem = -1;
            };
          };
          _this.ssSkill[j].NeedDay[i] = days;
        };
      };
    },

    mSfClickContextMenu(idx) { // 部隊編成：コンテキストメニュー
      let _this = this;
      if (_this.coTouchDevice == false) {
        _this.mSfClickContextMenuCom(idx);
      };
    },

    mSfClickContextMenuCom(idx) { // 部隊編成：コンテキストメニュー
      let _this = this;
      
      if (idx == 1) {
        // スキル詳細
        //_this.mSfSetFsEmphasis(_this.sfContextTarget.id);
      
      } else if (idx == 2) {
        // 強調切り替え
        _this.mSfSetFsEmphasis();
      
      } else if (idx == 3) {
        // グレーアウト切り替え
        _this.mSfSetFsGrayOut();

      } else if (idx == 4) {
        // 部隊バフ切り替え
        if (_this.sfContextTarget.parentNode.id.startsWith("sfSquad")) {
          let idx = _this.sfContextTarget.parentNode.id.replace("sfSquad", "");
          _this.mSetSquadBufIdx(idx);
        };

      } else if (idx == 5) {
        // キャラコピー
        _this.mSfNikkeCopy();

      } else if (idx == 6) {
        // キャラ消去
        _this.mSfNikkeRemove();

      } else if (idx == 11) {
        // 部隊交換：上
        idx = Number(_this.sfContextTarget.parentNode.id.replace("sfSquadSet", ""));
        if (_this.sfDispDirection == 2 || _this.isWidth820) {
          if (idx-1 >= 1) _this.mSfExchangeSquad(idx-1, idx);
        } else {
          if (idx == 3) _this.mSfExchangeSquad(1, 3);
          else if (idx == 4) _this.mSfExchangeSquad(2, 4);
          else if (idx == 5) _this.mSfExchangeSquad(3, 5);
          else if (idx == 6) _this.mSfExchangeSquad(4, 6);
        };
        
      } else if (idx == 12) {
        // 部隊交換：横
        let idx = Number(_this.sfContextTarget.parentNode.id.replace("sfSquadSet", ""));
        if (idx == 1 || idx == 2) _this.mSfExchangeSquad(1, 2);
        else if (idx == 3 || idx == 4) _this.mSfExchangeSquad(3, 4);
        else if (idx == 5 || idx == 6) _this.mSfExchangeSquad(5, 6);
      
      } else if (idx == 13) {
        // 部隊交換：下
        let idx = Number(_this.sfContextTarget.parentNode.id.replace("sfSquadSet", ""));
        if (_this.sfDispDirection == 2 || _this.isWidth820) {
          if (idx+1 <= 6) _this.mSfExchangeSquad(idx, idx+1);
        } else {
          if (idx == 1) _this.mSfExchangeSquad(1, 3);
          else if (idx == 2) _this.mSfExchangeSquad(2, 4);
          else if (idx == 3) _this.mSfExchangeSquad(3, 5);
          else if (idx == 4) _this.mSfExchangeSquad(4, 6);
        };
      };
    },

    mSfSetFsEmphasis() { // 部隊編成：強調切り替え
      let _this = this;
      let nikkeElementId = _this.sfContextTarget.id;
      let nikke = _this.nikkes.find( d => { return d.id === nikkeElementId.replace("sfnikke", "nikke"); });

      if (nikke.emphasis == 0) {
        nikke.emphasis = 1;
      } else {
        nikke.emphasis = 0;
      };
      _this.$set(_this.nikkes, 0, _this.nikkes[0]); // 配列でも画面へ即時反映されるようsetする

      // ローカルストレージへ強調表示を保存（コピーの場合は保存しない）
      if (!nikke.id.includes("_copy@")) {
        const nikkeNo = nikke.originId;
        let before = _this.fsEmphasisList.slice(0, nikkeNo-1);
        let after = _this.fsEmphasisList.slice(nikkeNo);
        _this.fsEmphasisList = before + nikke.emphasis + after;
        localStorage.setItem('fsEmphasisList', _this.fsEmphasisList);
      };
    },

    mSfSetFsGrayOut() { // 部隊編成：グレーアウト切り替え
      let _this = this;
      let nikkeElementId = _this.sfContextTarget.id;
      let nikke = _this.nikkes.find( d => { return d.id === nikkeElementId.replace("sfnikke", "nikke"); });

      if (nikke.grayout == 0) {
        nikke.grayout = 1;
      } else {
        nikke.grayout = 0;
      };
      _this.$set(_this.nikkes, 0, _this.nikkes[0]); // 配列でも画面へ即時反映されるようsetする

      // ローカルストレージへ強調表示を保存
      if (!nikke.id.includes("_copy@")) {
        const nikkeNo = nikke.originId;
        let before = _this.fsGrayOutList.slice(0, nikkeNo-1);
        let after = _this.fsGrayOutList.slice(nikkeNo);
        _this.fsGrayOutList = before + nikke.grayout + after;
        localStorage.setItem('fsGrayOutList', _this.fsGrayOutList);
      };
    },

    mSfNikkeCopy() { // 部隊編成：キャラコピー
      let _this = this;
      //let copyElement = document.getElementById(_this.sfContextTarget.id).cloneNode(true);
      let squadElement = document.getElementById(_this.sfContextTarget.parentNode.id);

      // 使用されていないIDを探す（永久ループ回避で探す範囲を上限1000件とする）
      let orgNikkeId = _this.sfContextTarget.id.split("_copy")[0].replace("sfnikke","nikke");
      let newNikkeId = ""
      for (let lpCnt=1; lpCnt<=1000; ++lpCnt) {
        newNikkeId = orgNikkeId + "_copy" + "@".repeat(lpCnt);
        if (document.getElementById("sf" + newNikkeId) == null) {
          lpCnt = 10000;
        };
      };

      // ニケ一覧にコピーを追加
      let newNikke = JSON.parse(JSON.stringify(_this.nikkes.find( d => { return d.id === orgNikkeId; })));
      newNikke.id = newNikkeId;
      newNikke.emphasis = 0;
      newNikke.grayout = 0;
      _this.nikkes.push(newNikke);
      _this.$set(_this.nikkes, 0, _this.nikkes[0]); // 配列でも画面へ即時反映されるようsetする

      // 遅延処理（ソートが反映される前に実行するとエラーが発生するため遅延させる）
      _this.mSfNikkeCopy_Delay(newNikkeId, squadElement, 50);
    },

    async mSfNikkeCopy_Delay(newNikkeId, squadElement, millisec) { // 部隊編成：ニケ並び順変更の遅延処理
      let _this = this;
      // 指定ミリ秒待機
      await _this.mCoSleepByPromise(millisec);
      // キャラコピー
      _this.mSfNikkeCopy_After(newNikkeId, squadElement);
    },

    mSfNikkeCopy_After(newNikkeId, squadElement) {
      let _this = this;
      let copyElement = document.getElementById("sf"+newNikkeId);

      // コピーするキャラが部隊の枠の中の何番目の要素なのか探す
      let cnt = 0;
      let idxTo = squadElement.childNodes.length; // ドロップ先の要素番号（デフォルトは最大値＝末尾）
      squadElement.childNodes.forEach(function(item){
        if(item.id == copyElement.id) idxTo = cnt+1;
        ++cnt;
      });

      squadElement.insertBefore(copyElement, squadElement.childNodes.item(idxTo)); // ドロップ先画像を挿入
      copyElement.style.position = "relative";
      copyElement.style.top = "0px";
      copyElement.style.left = "0px";
      copyElement.style.zIndex = 1;

      _this.mSaveQf(_this.sqSquadSelect);
    },

    mSfNikkeRemove() { // 部隊編成：キャラ消去
      let _this = this;
      let removeNikkeId = _this.sfContextTarget.id.replace("sfnikke","nikke");

      // ニケ一覧からコピーを削除
      _this.nikkes = _this.nikkes.filter(function(nikke) { 
