    mSfExchangeSquad(idx1, idx2) { // 部隊編成：部隊入れ替え
      let _this = this;

      // 部隊名入れ替え
      let squadName1 = _this.sqSquadNamePieces[idx1-1];
      let squadName2 = _this.sqSquadNamePieces[idx2-1];
      if (squadName1 == null) squadName1 = "";
      if (squadName2 == null) squadName2 = "";
      _this.sqSquadNamePieces[idx1-1] = squadName2;
      _this.sqSquadNamePieces[idx2-1] = squadName1;
      localStorage.setItem('sqSquadNamePieces_' + _this.sqSquadSelect + '_' + idx1, squadName2);
      localStorage.setItem('sqSquadNamePieces_' + _this.sqSquadSelect + '_' + idx2, squadName1);

      // 部隊メンバー入れ替え
      let squadMember1 = localStorage.getItem('sfSquad' + idx1 + "_" + _this.sqSquadSelect, 1);
      let squadMember2 = localStorage.getItem('sfSquad' + idx2 + "_" + _this.sqSquadSelect, 1);
      localStorage.setItem('sfSquad' + idx1 + '_' + _this.sqSquadSelect, squadMember2);
      localStorage.setItem('sfSquad' + idx2 + '_' + _this.sqSquadSelect, squadMember1);

      let squad1 = document.getElementById("sfSquad" + idx1);
      let squad2 = document.getElementById("sfSquad" + idx2);
      let squadBuf = document.createElement("div");
      let squad1Num = squad1.childNodes.length;
      let squad2Num = squad2.childNodes.length;
      for(let i = 1; i <= squad1Num; ++i){
        squadBuf.appendChild(squad1.childNodes[0]);
      };
      for(let i = 1; i <= squad2Num; ++i){
        squad1.appendChild(squad2.childNodes[0]);
      };
      for(let i = 1; i <= squad1Num; ++i){
        squad2.appendChild(squadBuf.childNodes[0]);
      };
      squadBuf.remove();
      
      _this.$set(_this.sqSquadNamePieces, 0, _this.sqSquadNamePieces[0]);
      _this.mSetSquadBuf();  // 部隊バフ一覧セット
    },

    mCoUpdateInfoConfirm() { // 共通：
      let _this = this;
      if (_this.coUpdateInfoNextFlg) {
        localStorage.setItem('coUpdateDispVer', _this.coUpdateDispVerMax);
        //_this.coUpdateDispCheck = "checked";
      };
    },

    mUsCaptureStart() { // 面談サポート：画面キャプチャ開始
      let _this = this;
      let videoContainer = document.querySelector("div#capture-stream");

      Cap();
      async function Cap() {
        _this.tsCaptureStream = await navigator.mediaDevices.getDisplayMedia({audio: false, video: true});
        videoContainer.innerHTML = '';
        if (_this.tsCaptureStream) {
          const video = document.createElement("video");
          video.autoplay = true;
          video.srcObject = _this.tsCaptureStream;
          videoContainer.appendChild(video);
          //takeScreenshotsButton.removeAttribute("disabled")

          if(_this.tsCaptureInterval != null) {
            clearInterval(_this.tsCaptureInterval);
            _this.tsCaptureInterval = null;
          };
          _this.mUrTakeScreenshot();
        };
      };
    },

    mUsChangeCaptureIntervalTime() { // ユニオンレイド：
      let _this = this;
      if(_this.tsCaptureInterval != null) {
        clearInterval(_this.tsCaptureInterval);
        _this.tsCaptureInterval = null;
        _this.mUrTakeScreenshot();
      };
      localStorage.setItem('tsCaptureIntervalTime', _this.tsCaptureIntervalTime);
