                    let captureCanvasName = document.getElementById('usCanvasName');
                    let captureContextName = captureCanvasName.getContext('2d',{ willReadFrequently: true });
                    captureContextName.drawImage(imageBitmap, sx, sy, dx, dy, 0, 0, cutWidth*4, cutHeight*4);
                    let buf = document.querySelector('#usCanvasName');
