                        let trig2 = _this.trigramify(buf);
                        _this.usMemberList.forEach(function(member){
                          let trig1 = _this.trigramify(member);
                          let hit = _this.relevance(trig1, trig2); //比較
                          if (hit > maxhit) {
                            maxhit = hit;
                            buf = member;
