                    sx = Math.round(canvas.width/2 - 193);            // 読み取り部分の左上x座標
                    dx = Math.round(cutWidth * canvas.height/983);    // 読み取り部分の幅
                    sy = 275 + y + 3;                                 // 読み取り部分の左上y座標
