                    let dst = captureContextScore.createImageData(cutWidth*4, cutHeight*4);
                    let prt = [];
                    let row = [];
                    for (let i = 0; i < src.data.length; i += 4) {
                      let y = 0.2126 * src.data[i] + 0.7152 * src.data[i + 1]
