                        //}
                        
                        if (dots.length >= 1) {
                          if (dots.endsWith(prt[rowIdx][colIdx])) {
                            dots += prt[rowIdx][colIdx] + "";
                          } else {
                            dots = prt[rowIdx][colIdx] + "";
                          };
                        } else {
                          dots = prt[rowIdx][colIdx] + "";
                        };
                        
                        if      (flgZeroOne == 0 && dots == "11111111") { if (disp >= 1 || rowIdx <= (prt.length*0.8)) { flgZeroOne = 1; ++disp; } } // 1が3回連続した場合
                        else if (flgZeroOne == 1 && dots == "000") { flgZeroOne = 0; }          // 0が3回連続した場合
                        else if (flgOneCols <= 8 && disp == 1 && dots == "11111111111111111111") { flg5 = true; }  // 数字列の前半 && 最初の1連続群 && 1が20回連続した場合
