                      };

                      if (number == "") {
                        if (disp >= 1) number = disp + "";
                      } else if (disp >= 1 && !number.endsWith(disp)) {
                        number += disp + "";
                      } else if (disp == 0) {
                        numbers.push(number);
                        number = "";
                      };

                      if (disp >= 1) ++flgOneCols;  // 連続する1の群があった場合
