                      else if (numbers[i] == "12321") nums += "5";
                      else if (numbers[i] == "1232") nums += "5";
                      else if (numbers[i] == "232") nums += "5";
                      else if (numbers[i] == "132") nums += "6";
                      else if (numbers[i] == "1321") nums += "6";
                      else if (numbers[i] == "121") nums += "7";
                      else if (numbers[i] == "21312") nums += "8";
