                      else if (numbers[i] == "213121") nums += "8";
                      else if (numbers[i] == "1213121") nums += "8";
                      else if (numbers[i] == "231") nums += "9";
                      else if (numbers[i] == "1231") nums += "9";
                      else nums += "判別不能["+numbers[i]+"]";
                    };

                    buf = document.querySelector('#usCanvasScore');
                    Tesseract.recognize(buf, 'eng',
                      { logger: function(m) { document.querySelector('#tsOcrProgressAuto').textContent = m.status; } }
                    )
                    .then(function(result){
                        let buf = result.data.text;
                        buf = buf.replace(/\s+/g, ''); // スペース削除
                        buf = buf.replace(/,/g, '');   // カンマ削除
                        buf = buf.replace(/\./g, '');  // ドット削除
