                        };
                    });
                  };
                };
              };

              document.querySelector('#tsOcrProgressAuto').textContent = "Select Window not found...";

            } catch(e) {
              clearInterval(_this.tsCaptureInterval);
              _this.tsCaptureInterval = null;
            };
          } else {
            document.querySelector('#tsOcrProgressAuto').textContent = "Found!";
          };
        };
      }, interTime);
