        _this.sdDispResultXMax = _this.sdDispResultXMin + 1
      };
      
      // ローカルストレージへ設定内容を保存
      localStorage.setItem('sdDispResultXMax', _this.sdDispResultXMax);
      localStorage.setItem('sdDispResultXMin', _this.sdDispResultXMin);
      
      _this.mSdCalc();
    },

    mSdChangeResultXMax() { // ソロレデータ：ボーダー推移検索範囲変更
      let _this = this;
      if (_this.sdDispResultXMax < 1) {
        _this.sdDispResultXMax = 1;
      } else if (_this.sdDispResultXMax > 50) {
        _this.sdDispResultXMax = 50;
      } else {
