      };

      if (_this.sdDispResultXMin >= _this.sdDispResultXMax) {
        _this.sdDispResultXMin = _this.sdDispResultXMax - 1
      };
      
      // ローカルストレージへ設定内容を保存
      localStorage.setItem('sdDispResultXMax', _this.sdDispResultXMax);
      localStorage.setItem('sdDispResultXMin', _this.sdDispResultXMin);
      
      _this.mSdCalc();
    },

    mSdChangeBoss(id) { // ソロレデータ：表示対象ボス指定
      let _this = this;

      _this.sdSelectBossId = [];

      _this.soloraid.forEach(function(raid){
        if (raid.id == id) {
          // 指定されたidのチェック状態を反転
          raid.check = !raid.check;

          // チェック履歴に登録または削除
          if (raid.check) {
            _this.sdCheckHistory.push(raid.id);
          } else {
            _this.sdCheckHistory = _this.sdCheckHistory.filter(n => n !== raid.id);
          };
        };

        // チェック状態がxx点以上の場合は一番古いチェック(履歴の先頭)をOFFにする
        if (_this.sdCheckHistory.length >= 13) {
          let firstHistId = _this.sdCheckHistory[0];
          _this.soloraid.forEach(function(raid){
            if (raid.id == firstHistId) {
              raid.check = false;
              _this.sdCheckHistory.shift(); // 先頭の要素を削除
            };
          });
        };

        if (raid.check == true) {
          _this.sdSelectBossId.push(raid.id);
        };
      });

      // ローカルストレージへ設定内容を保存
      localStorage.setItem('sdSelectBossId', _this.sdSelectBossId);

      _this.mSdCalc();
    },

