    async mSdCalc() { // ソロレデータ：計算
      let _this = this;

      // 初期設定
      if (_this.soloraid[0].id == 0) {
        _this.soloraid = [];

        //外部JSON読み込み
        //for (let i=25; i>=10; --i) {
        //  await axios.get(_this.urlSoloraidJson + i + '.json').then(function(response) {soloraidJson = response.data;}.bind(_this)).catch(function(e) {console.error(e)});
        //  _this.soloraid.push(JSON.parse(JSON.stringify(soloraidJson)));
        //};
        await axios.get(_this.urlSoloraidJson).then(function(response) {_this.soloraid = response.data;}.bind(_this)).catch(function(e) {console.error(e)});
        _this.soloraid.reverse();

        // ソロレイド最新データ桁変更（Ｍ⇒億）
        _this.soloraid.forEach(function(raid){
          raid.dataList.forEach(function(data){
            data.score /= 100;
          });
        });

        // ソロレイド最新データ日時
        _this.soloraid[0].dataList.forEach(function(data){
          if (_this.sdNewestDate < data.datetime) {
            _this.sdNewestDate = data.datetime;
          };
        });
        _this.sdNewestDate = new Date(_this.sdNewestDate)
        var basedate = new Date(_this.soloraid[0].basedate);
        _this.sdNewestDate.setFullYear(basedate.getFullYear());
        _this.sdNewestDate.setMonth(_this.sdNewestDate.getMonth() + basedate.getMonth());
        _this.sdNewestDate.setDate(_this.sdNewestDate.getDate() + basedate.getDate() - 1);
        _this.sdNewestDate.setHours(_this.sdNewestDate.getHours() + basedate.getHours());
        _this.sdNewestDate.setMinutes(_this.sdNewestDate.getMinutes() + basedate.getMinutes());
        _this.sdNewestDate.setSeconds(_this.sdNewestDate.getSeconds() + basedate.getSeconds());
        
        // 過去ソロレイド初期選択
        let flgSelect = false;
        _this.soloraid.forEach(function(raid){
          if (raid.holding == true || _this.sdSelectBossId.includes(raid.id.toString())) {
            raid.check = true;
            flgSelect = true;
          };
        });
        if (flgSelect == false) {
          _this.soloraid[0].check = true;
          _this.soloraid[1].check = true;
          _this.soloraid[2].check = true;
        };
        _this.mSdChangeBoss(0);
