        //_this.mSdChangeBoss(_this.soloraid[1].id);
        //_this.mSdChangeBoss(_this.soloraid[2].id);
      };

      // ボーダー予想表示
      if (_this.soloraid[0].holding == true && _this.soloraid[0].check == true) {
        _this.sdDispGuessBorder = true;
      } else {
