    mOsMakeChart(flgAdd) { // オバロシミュ：グラフ生成
      let _this = this;

      // シミュレーション回数が上限下限を超えている場合は是正
      if (_this.osSimuNum < 1) _this.osSimuNum = 1;
      if (_this.osSimuNum > 1000000) _this.osSimuNum = 1000000;

      // 効果・数値リロール最大数
      if (_this.osRerollNum < 1) _this.osRerollNum = 1;
      if (_this.osRerollNum > 1000) _this.osRerollNum = 1000;

      // シミュレーション10000回実行
      if (flgAdd) {
        for (let i=1; i<=_this.osSimuNum; ++i) {
          let customNum = 0;          // カスモ消費数
          let parts = [-1, -1, -1];   // 上中下段のオプション的中状態 0:未的中、1:的中済み
          let optionHit = [0, 0, 0];  // オプション1～3の的中状態 0:未的中、1:的中済み
          let stepHit = [0, 0, 0];    // 数値1～3の的中状態 0:未的中、1:的中済み
          let lockNum = 0;            // ロック個所数
          let goalFlg = false;        // 目標達成フラグ

          for (let j=0; j<=2; ++j) {
            _this.osDataList[0].datas[j].effectHit = false;
            _this.osDataList[0].datas[j].stepHit = false;
          };

          // 効果変更を最大200回実行
          if (_this.osDataList[0].effectCalc) {
            for (let j=1; j<=_this.osRerollNum; ++j) {
              customNum += 1 + lockNum;   // カスモ消費数を加算（ロック数により消費が増える）

              //if (_this.osDataList[0].configurable[2] == false) parts[2] = 99;  // 下段設定可能個所

              // オプション指定3個所の効果的中判定を順に実施
              for (let k=0; k<=2; ++k) {
                // オプション指定有り、且つ、非的中状態の場合は判定を実施
                if (_this.osDataList[0].datas[k].optionId >= 1 && optionHit[k] == 0) {
                  let rnd = Math.random();  // 乱数値0.000...～1.000...

                  // 効果の上中下段確率>=乱数値以下の場合は的中とする
                  if (_this.osDataList[0].configurable[2] == true && parts[2] == -1 && _this.osDataList[0].datas[k].effectPartProb[2] >= rnd) {
                    if (_this.osEffectLockThreshold >= 1) {
                      ++lockNum;
                      if (lockNum == 1) customNum += 2;
                      if (lockNum == 2) customNum += 3;
                    };
                    parts[2] = k;
                    optionHit[k] = 1;
                  } else if (_this.osDataList[0].configurable[1] == true && parts[1] == -1 && _this.osDataList[0].datas[k].effectPartProb[1] >= rnd) {
                    if (_this.osEffectLockThreshold == 1
                        || _this.osEffectLockThreshold == 2
                        || (_this.osEffectLockThreshold == 3 && parts[2] != -1)) {
                      ++lockNum;
                      if (lockNum == 1) customNum += 2;
                      if (lockNum == 2) customNum += 3;
                    }
                    parts[1] = k;
                    optionHit[k] = 1;
                  } else if (_this.osDataList[0].configurable[0] == true && parts[0] == -1 && _this.osDataList[0].datas[k].effectPartProb[0] >= rnd) {
                    if (_this.osEffectLockThreshold == 1) {
                      ++lockNum;  // ロック
                      if (lockNum == 1) customNum += 2;
                      if (lockNum == 2) customNum += 3;
                    };
                    parts[0] = k;
                    optionHit[k] = 1;
                  };
                } else {
                  optionHit[k] = 1;
                };
              };

              if (optionHit[0]+optionHit[1]+optionHit[2] == 3) {
                goalFlg = true;
                break;
              } else {
                if (_this.osEffectLockThreshold == 0) { // ロックしない場合は上中下段を全て解放
                  if (parts[0] >= 0) optionHit[parts[0]] = 0;
                  if (parts[1] >= 0) optionHit[parts[1]] = 0;
                  if (parts[2] >= 0) optionHit[parts[2]] = 0;
                  parts[0] = -1;
                  parts[1] = -1;
                  parts[2] = -1;
                } else if (_this.osEffectLockThreshold == 2) { // 中下段ロックの場合は上段を解放
                  if (parts[0] >= 0) optionHit[parts[0]] = 0;
                  parts[0] = -1;
                } else if (_this.osEffectLockThreshold == 3 && parts[2] != -1) { // 「下段が埋まったら中段」で下段が埋まっている場合は上段を解放
                  if (parts[0] >= 0) optionHit[parts[0]] = 0;
                  parts[0] = -1;
                } else if (_this.osEffectLockThreshold == 3 && parts[2] == -1) { // 「下段が埋まったら中段」で下段が埋まっていない場合は上中段を解放
                  if (parts[0] >= 0) optionHit[parts[0]] = 0;
                  if (parts[1] >= 0) optionHit[parts[1]] = 0;
                  parts[0] = -1;
                  parts[1] = -1;
                } else if (_this.osEffectLockThreshold == 4) { // 下段ロックの場合は上中段を解放
                  if (parts[0] >= 0) optionHit[parts[0]] = 0;
                  if (parts[1] >= 0) optionHit[parts[1]] = 0;
                  parts[0] = -1;
                  parts[1] = -1;
                }
              };
            };
          } else {
            goalFlg = true;
          }

          // 数値変更を最大200回実行
          if (goalFlg) {
            lockNum = 0;  // ロック数リセット
            goalFlg = false;
            for (let j=1; j<=_this.osRerollNum; ++j) {
              customNum += 1 + lockNum;   // カスモ消費数を加算（ロック数により消費が増える）

              // オプション指定3個所の効果的中判定を順に実施
              for (let k=0; k<=2; ++k) {
                // オプション指定有り、且つ、非的中状態の場合は判定を実施
                if (_this.osDataList[0].datas[k].optionId >= 1 && _this.osDataList[0].datas[k].goalStep >= 1 && stepHit[k] == 0) {
                  //let rnd = Math.floor(Math.random() * 101);  // 乱数値0～100
                  let rnd = Math.random();  // 乱数値0.000...～1.000...

                  // 数値の確率>=乱数値以下の場合は的中とする
                  if (stepHit[k] == 0 && _this.osDataList[0].datas[k].stepAppearance >= rnd) {
                    if (_this.osStepLockThreshold <= _this.osDataList[0].datas[k].goalStep) {
                      ++lockNum;
                      if (lockNum == 1) customNum += 2;
                      if (lockNum == 2) customNum += 3;
                    };
                    stepHit[k] = 1;
                  };
                } else {
                  stepHit[k] = 1;
                };
              };

              if (stepHit[0]+stepHit[1]+stepHit[2] == 3) {
                goalFlg = true;
                break;
              } else {
                // 目標が数値ロック条件未満の箇所は解放
                if (_this.osStepLockThreshold > _this.osDataList[0].datas[0].goalStep) stepHit[0] = 0;
                if (_this.osStepLockThreshold > _this.osDataList[0].datas[1].goalStep) stepHit[1] = 0;
                if (_this.osStepLockThreshold > _this.osDataList[0].datas[2].goalStep) stepHit[2] = 0;
              };
            };
          };

          // 目標に到達している場合のみ結果格納
          if (goalFlg) {
            let chart = _this.osChartDataList.find(e => e.x === customNum);
            if (chart == undefined) {
              let newChart = JSON.parse(JSON.stringify(_this.osChartData));
              newChart.x = customNum;
              newChart.num = 1;
              _this.osChartDataList.push(newChart);
            } else {
              chart.num++;
            };
          };
        };
      };

      // グラフデータをカスモ消費量で昇順ソート
      _this.osChartDataList.sort((a,b) => {
        if (a.x > b.x) { return 1 }
        if (a.x < b.x) { return -1 }
      }); 
      
      // 目標到達回数の最大値と合計を取得
      let totalReached = 0;
      _this.osChartDataList.forEach(function(chart){
        //if (maxReached < chart.num) maxReached = chart.num;
        totalReached += chart.num;
      });

      _this.osChartProportionList.splice(0); // 初期化
      _this.osDataList[0].totalCustomNum = -1; // 初期化
      let countReached = 0; // 目標到達回数(累計)

      // カスモ消費量の比率を算出
      _this.osChartDataList.forEach(function(chart){
        let newProp = JSON.parse(JSON.stringify(_this.osChartProportion));
        countReached += chart.num;
        newProp.customNum = chart.x;
        newProp.proportion = countReached / totalReached * 100;
        _this.osChartProportionList.push(newProp);

        if (_this.osDataList[0].totalCustomNum == -1 && newProp.proportion >= 50) {
          _this.osDataList[0].totalCustomNum = newProp.customNum; // 50%時点のカスモ必要数
        };
      });

      // 目標到達回数を％に変更
      let preNumY = 0;
      _this.osChartDataList.forEach(function(chart){
        chart.y = (preNumY + chart.num) / totalReached * 100;
        preNumY += chart.num;
      });

      // グラフ生成
      const ctx = document.getElementById('myChart').getContext('2d');
      //for (let i=1; i<=2; ++i) {
        // 1週目で縦軸最大値を確認し、2週目で50%ラインの値を設定する
        //var maxReached = 0;
        //if (i == 2) {
        //  maxReached = _this.osChart.scales.y.max;
        //  _this.osChart.destroy();
        //};
      if (_this.osChart != null) _this.osChart.destroy();
      _this.osChart = new Chart(ctx, {
        data: {
          datasets: [
            {
              type: 'scatter',
              label: "カスモ消費数",
              data: _this.osChartDataList,
              yID: 'y-axis-1',
              showLine: true,
            },
            {
              type: 'line',
              label: "50%ライン",
              data: [
                 { x: _this.osDataList[0].totalCustomNum, y: 0 }
                //,{ x: _this.osDataList[0].totalCustomNum, y: maxReached }
                ,{ x: _this.osDataList[0].totalCustomNum, y: 100 }
              ],
              yID: 'y-axis-2',
              borderWidth: 1,
              fill: false,
              lineTension: 0,
            }
          ],
        },
        plugins: [
            ChartDataLabels,
        ],
        options: {
          plugins: {
            title: {
              display: true,
              text: "シミュレーション結果",
              font: {
                size: 16
              }
            },
            legend: { // 凡例
              display: false,
              position: 'chartArea',
              //align: 'start',
              //fullSize: 'false',
            },
            tooltip: {
              callbacks: {
                label: function (tooltipItem, data) {
                  if (tooltipItem.label == "") {
                    //var customNum = tooltipItem.raw.x;
                    //var chartProp = _this.osChartProportionList.find(e => e.customNum === tooltipItem.raw.x);
                    //var proportion = "--";
                    //if (chartProp) proportion = chartProp.proportion.toFixed(2);
                    var labels = [
                      "カスモ消費数：" + tooltipItem.raw.x
                      ,"目標到達確率：" + tooltipItem.raw.y.toFixed(2) + "%"
                      //,"目標到達確率：" + proportion + "%"
                    ];
                    return labels;
                  } else {
                    tooltipItem.label = "";
                    var labels = ["50%ライン"];
                    return labels;
                  };
                },
              },
            },
