    mCoSetDark(flgChange) { // 共通：ダークモード設定
      let _this = this;
  
      if (flgChange) {
        if (_this.isDark == 0) {
          _this.isDark = 1;
        } else {
          _this.isDark = 0;
        };
      };

      if (_this.isDark == 1) {
        document.documentElement.setAttribute("class", "dark");
      } else {
        document.documentElement.setAttribute("class", "");
      };
      localStorage.setItem('isDark', _this.isDark);
    },

    mCoMouseLeaveNikkeSort() { // 共通：ニケ並び順変更ボタンマウスリーブ
      let _this = this;
      // フラグを全クリア
      _this.coNikkeSortKey.forEach(function(nikkeSort){
        nikkeSort.MouseOverFlg = false;
      });
    },

    mCoMouseOverNikkeSort(orgIdx) { // 共通：ニケ並び順変更ボタンマウスオーバー
      let _this = this;
      let cnt = 0;
      let idx1 = 0;
      let idx2 = 0;

      // マウスオーバーされたキーの配列番号を取得
      cnt = 0;
      _this.coNikkeSortKey.forEach(function(nikkeSort){
        if(nikkeSort.Idx == orgIdx) {
          idx1 = cnt;
        } else {
          ++cnt;
        };
      });

      // マウスオーバーされたキーの1つ下のキーの配列番号を取得
      cnt = 0;
      _this.coNikkeSortKey.forEach(function(nikkeSort){
        if((nikkeSort.SortNum - 1) == _this.coNikkeSortKey[idx1].SortNum) {
          idx2 = cnt;
        } else {
          ++cnt;
        };
      });

      // フラグを全クリア
      _this.coNikkeSortKey.forEach(function(nikkeSort){
        nikkeSort.MouseOverFlg = false;
      });

      // フラグをセット
      _this.coNikkeSortKey[idx1].MouseOverFlg = true;
      _this.coNikkeSortKey[idx2].MouseOverFlg = true;
    },

    mCoChangeNikkeSortKey(orgIdx, upDown) { // 共通：ニケ並び順変更
      let _this = this;
      let cnt = 0;
      let idx = 0;
      let flgExec = 0;

      // クリックされたキーの配列番号を取得
      _this.coNikkeSortKey.forEach(function(nikkeSort){
        if(nikkeSort.Idx == orgIdx) {
          idx = cnt;
        } else {
          ++cnt;
        };
      });

      _this.coNikkeSortKey.forEach(function(nikkeSort){
        if(flgExec == 0) {
          if(nikkeSort.SortNum == (Number(_this.coNikkeSortKey[idx].SortNum) + Number(upDown))){
            nikkeSort.SortNum = Number(nikkeSort.SortNum) + (Number(upDown) * (-1));
            flgExec = 1;
          };
        };
      });
      _this.coNikkeSortKey[idx].SortNum = Number(_this.coNikkeSortKey[idx].SortNum) + Number(upDown);

      // ニケ並び順配列を並び替え
      _this.coNikkeSortKey.sort((a,b) => {
        if (a.SortNum > b.SortNum) { return 1 }
        if (a.SortNum < b.SortNum) { return -1 }
      });

      // 並び順付け替え＆保存
      let num = 1;
      _this.coNikkeSortKey.forEach(function(nikkeSort){
        nikkeSort.SortNum = num++;
        localStorage.setItem('coNikkeSortKey['+nikkeSort.Idx+']', nikkeSort.SortNum);
      });

      _this.mCoChangeNikkeSort();
    },

    mCoChangeNikkeSort() { // 共通：ニケ並び順変更
      let _this = this;

      // ニケ一覧を並び替え
      _this.nikkes.forEach(function(nikke){
        nikke.allSort = nikke.grayout;
        //nikke.allSort = "";
        _this.coNikkeSortKey.forEach(function(nikkeSort){
          if(nikkeSort.Name == "名前") {
            nikke.allSort += String(nikke.name).padEnd(20, "＿");
          } else if(nikkeSort.Name == "等級") {
            nikke.allSort += String(nikke.rearitySort).padStart(3, "0");
          } else if(nikkeSort.Name == "バースト") {
            nikke.allSort += String(nikke.burstclassSort).padStart(3, "0");
          } else if(nikkeSort.Name == "属性") {
            nikke.allSort += String(nikke.elementalSort).padStart(3, "0");
          } else if(nikkeSort.Name == "武器") {
            nikke.allSort += String(nikke.weaponSort).padStart(3, "0");
          } else if(nikkeSort.Name == "クラス") {
            nikke.allSort += String(nikke.classSort).padStart(3, "0");
          } else if(nikkeSort.Name == "企業") {
            nikke.allSort += String(nikke.manufacturerSort).padStart(3, "0");
          } else if(nikkeSort.Name == "実装順") {
            nikke.allSort += String(10000 - nikke.implementation).padStart(3, "0");
          };
        });
      });

      // 部隊1～6に配置されたニケを一旦戻す
      _this.mSfClearNikke(false);

      // 四象限の配置をクリア
      _this.mSmClearNikke("");
      
      // ソート実行
      _this.nikkes.sort((a,b) => {
        if (a.allSort > b.allSort) { return 1 }
        if (a.allSort < b.allSort) { return -1 }
      });

      // 遅延処理（ソートが反映される前に実行するとエラーが発生するため遅延させる）
      _this.mCoChangeNikkeSort_Delay(50);
    },

    async mCoChangeNikkeSort_Delay(millisec) { // 部隊編成：ニケ並び順変更の遅延処理
        let _this = this;
        // 指定ミリ秒待機
        await _this.mCoSleepByPromise(millisec);
        // 部隊ロード
        _this.mLoadQf(_this.sqSquadSelect);
    },

    mCoSleepByPromise(millisec) { // 指定ミリ秒待機
      return new Promise(resolve => setTimeout(resolve, millisec));
    },

    async mTsInit() {  // 面談サポート：初期設定
      let _this = this;

      if (_this.talks.length != 0) return;
      
      //外部JSON読み込み
      await axios.get(_this.urlTalkJson).then(function(response) {_this.talks = response.data;}.bind(_this)).catch(function(e) {console.error(e)});

      // 面談データを加工
      _this.talks.forEach(function(nikke){
        let margeSelect = "";
        let margeHiragana = "";
        nikke.cases.forEach(function(caseItem){ // 選択肢1～2
          //caseItem.trigramify = _this.trigramify(caseItem.select); // マッチング用データ
          margeSelect += caseItem.select;
          margeHiragana += caseItem.hiragana;
        });
        nikke.select = margeSelect;                       // 選択肢(マージ)
        nikke.hiragana = margeHiragana;                   // 選択肢平仮名(マージ)
        nikke.trigramify = _this.trigramify(margeSelect); // マッチング用データ
        nikke.hit = 0;
      });
      
      // 面談候補ニケのリストを作成～並び替え
      _this.talks.forEach(function(nikke){
        if (!_this.tsTalkNikkes.some(item => item.name === nikke.name)) {
          let newNikke = JSON.parse(JSON.stringify(_this.tsTalkNikkeProt));
          newNikke.id = nikke.id;
          newNikke.name = nikke.name;
          newNikke.spriteNo = _this.nikkes.find(e => e.name === nikke.name).spriteNo;
          newNikke.costume  = _this.nikkes.find(e => e.name === nikke.name).costume;
          newNikke.rand     = _this.nikkes.find(e => e.name === nikke.name).rand;
          newNikke.allSort  = _this.nikkes.find(e => e.name === nikke.name).allSort;
          newNikke.burstclass = nikke.burstclass;
          newNikke.check = false;
          _this.tsTalkNikkes.push(newNikke);
        };
      });
      _this.tsTalkNikkes.sort((a,b) => {
        if (a.allSort > b.allSort) { return 1 }
        if (a.allSort < b.allSort) { return -1 }
      });
    },

