    mTsCaptureStart() { // 面談サポート：画面キャプチャ開始
      let _this = this;
      //let takeScreenshotsButton = document.querySelector("#take-screenshots");
      let videoContainer = document.querySelector("div#capture-stream");

      Cap();
      async function Cap() {
        _this.tsCaptureStream = await navigator.mediaDevices.getDisplayMedia({audio: false, video: true});
        videoContainer.innerHTML = '';
        if (_this.tsCaptureStream) {
          const video = document.createElement("video");
          video.autoplay = true;
          video.srcObject = _this.tsCaptureStream;
          videoContainer.appendChild(video);
          //takeScreenshotsButton.removeAttribute("disabled")

          if(_this.tsCaptureInterval != null) {
            clearInterval(_this.tsCaptureInterval);
            _this.tsCaptureInterval = null;
          };
          _this.mTsTakeScreenshot();
        };
      };
    },

    mTsTakeScreenshot() { // 面談サポート：スクリーンショット
      let _this = this;
      let interTime = _this.tsCaptureIntervalTime * 1000;


      _this.tsCaptureInterval = setInterval(function() {
        ScreenShot();
        async function ScreenShot() {
          _this.tsCaptureSkipSec -= Number(_this.tsCaptureIntervalTime);

          if(_this.tsCaptureSkipSec <= 0) {

            const videoTrack = _this.tsCaptureStream.getVideoTracks()[0];
            const imageCapture = new ImageCapture(videoTrack);
            let imageBitmap = null;
            try {
              imageBitmap = await imageCapture.grabFrame();

              //canvasContainer.innerHTML = '';
              const canvas = document.createElement("canvas");
              canvas.width = imageBitmap.width;
              canvas.height = imageBitmap.height;

              let sx = Math.round(canvas.width/2 - (400/2)*(canvas.height/983));  // 読み取り部分の左上x座標
              let dx = Math.round(400 * canvas.height/983);                       // 読み取り部分の幅
              let sy1 = Math.round(canvas.height * 622/983);                      // 読み取り部分の左上y座標(上選択肢)
              let dy = Math.round(canvas.height * 145/983);                       // 読み取り部分の高さ

              // 上選択肢の切り出し画像を作成
              let captureCanvas1 = document.getElementById('tsOutputCanvas1');
              let captureContext1 = captureCanvas1.getContext('2d',{ willReadFrequently: true });
              captureContext1.drawImage(imageBitmap, sx, sy1, dx, dy, 0, 0, 410, 145);

              // 面談画面（チェック箇所の背景が黒）の場合のみ処理
              let buf = document.querySelector('#tsOutputCanvas1');
              Tesseract.recognize(buf, 'jpn',
                  { logger: function(m) { 
                      //document.querySelector('#tsOcrProgressAuto').textContent = m.status;
                  } }
              )
              .then(function(result){
                  let buf = result.data.text;
                  buf = buf.replace(/\s+/g, ''); // スペース削除
                  buf = buf.replace(/①/g, '1'); // 数字
                  buf = buf.replace(/②/g, '2'); // 数字
                  buf = buf.replace(/③/g, '3'); // 数字
                  buf = buf.replace(/④/g, '4'); // 数字
                  buf = buf.replace(/⑤/g, '5'); // 数字
                  buf = buf.replace(/⑥/g, '6'); // 数字
                  buf = buf.replace(/⑦/g, '7'); // 数字
                  buf = buf.replace(/⑧/g, '8'); // 数字
                  buf = buf.replace(/⑨/g, '9'); // 数字
                  buf = buf.replace(/!/g, '！');
                  buf = buf.replace(/\?/g, '？');
                  _this.tsSearchWordCls = 1;
                  _this.tsSearchWord1 = buf;
              });

              // 上選択肢の補正画像を作成
              if(_this.tsImageCorr == 1) {
                let imageData1 = captureContext1.getImageData(1, 1, 410, 130);
                let xmin = 10000;
                let xmax = 0;
                let ymin = 10000;
                let ymax = 0;
                for(let x = 0; x < 410; x=x+5) {
                  for(let y = 0; y < 130; y=y+5) {
                    var r = imageData1.data[(x + y*410)*4];
                    if(r >= 100){
                      if(xmin > x) xmin = x;
                      if(xmax < x) xmax = x;
                      if(ymin > y) ymin = y;
                      if(ymax < y) ymax = y;
                    }
                  };
                };
                let sxn = sx+xmin-15;     // X軸始点（左上）
                let syn = sy1+ymin-5;     // Y軸始点（左上）
                let dxn = (xmax-xmin)+30; // X軸幅
                let dyn = (ymax-ymin)+10; // Y軸幅
                if(dyn < 25) dyn = 25;
                if(dxn > dyn/130*410) dyn = Math.round(dxn/410*130);
                if(dxn < dyn/130*410) dxn = Math.round(dyn/130*410);
                let captureCanvas1s = document.getElementById('tsOutputCanvas1s');
                let captureContext1s = captureCanvas1s.getContext('2d',{ willReadFrequently: true });
                captureContext1s.drawImage(imageBitmap, sxn, syn, dxn, dyn, 0, 0, 410, 130);
                buf = document.querySelector('#tsOutputCanvas1s');
                Tesseract.recognize(buf, 'jpn',
                    { logger: function(m) { 
                      //document.querySelector('#tsOcrProgressAuto').textContent = m.status;
                    } }
                )
                .then(function(result){
                    let buf = result.data.text;
                    buf = buf.replace(/\s+/g, ''); // スペース削除
                    buf = buf.replace(/①/g, '1'); // 数字
                    buf = buf.replace(/②/g, '2'); // 数字
                    buf = buf.replace(/③/g, '3'); // 数字
                    buf = buf.replace(/④/g, '4'); // 数字
                    buf = buf.replace(/⑤/g, '5'); // 数字
                    buf = buf.replace(/⑥/g, '6'); // 数字
                    buf = buf.replace(/⑦/g, '7'); // 数字
                    buf = buf.replace(/⑧/g, '8'); // 数字
                    buf = buf.replace(/⑨/g, '9'); // 数字
                    buf = buf.replace(/!/g, '！');
                    buf = buf.replace(/\?/g, '？');
                    _this.tsSearchWordCls = 1;
                    _this.tsSearchWord1s = buf;
                });

              } else {
                //document.querySelector('#tsOcrProgressAuto').textContent = "Select Window not found...";
              };

            } catch(e) {
              clearInterval(_this.tsCaptureInterval);
              _this.tsCaptureInterval = null;
            };
          } else {
            //document.querySelector('#tsOcrProgressAuto').textContent = "Found!";
          };
        };
      }, interTime);
    },

