    mLsPackCheck(id, chkOn) { // 育成：課金パック選択
      let _this = this;
      this.packs.forEach(function(pack){
        if(pack.id == id) {
          pack.check = pack.check * (-1);

          if (chkOn) {
            if (_this.selected[pack.id] === undefined) {
              _this.selected[pack.id] = true;
            } else {
              _this.selected[pack.id] = !_this.selected[pack.id];
            }
          }
        }
      })
      this.mCalcLeveling();
    },

    mCalcLeveling() { // 育成：レベリング計算
      let _this = this;

      _this.needs[0].NextLv = _this.coNikkeLv + 1;
      _this.needs[1].NextLv = Math.floor(_this.coNikkeLv / 20) * 20 + 21;
      _this.needs[2].NextLv = _this.needs[1].NextLv + 20;

      _this.lsPosCaseCredit[0] = parseInt(_this.lsPosCaseCredit[1])
                               + parseInt(_this.lsPosCaseCredit[2]) * 2
                               + parseInt(_this.lsPosCaseCredit[3]) * 4
                               + parseInt(_this.lsPosCaseCredit[4]) * 8
                               + parseInt(_this.lsPosCaseCredit[5]) * 12
                               + parseInt(_this.lsPosCaseCredit[6]) * 24
                               + parseInt(_this.lsPosCaseCredit[7]) * 30;

      _this.lsPosCaseBattle[0] = parseInt(_this.lsPosCaseBattle[1])
                               + parseInt(_this.lsPosCaseBattle[2]) * 2
                               + parseInt(_this.lsPosCaseBattle[3]) * 4
                               + parseInt(_this.lsPosCaseBattle[4]) * 8
                               + parseInt(_this.lsPosCaseBattle[5]) * 12
                               + parseInt(_this.lsPosCaseBattle[6]) * 24
                               + parseInt(_this.lsPosCaseBattle[7]) * 10;

      _this.lsPosCaseCore[0] = parseInt(_this.lsPosCaseCore[1])
                             + parseInt(_this.lsPosCaseCore[2]) * 2
                             + parseInt(_this.lsPosCaseCore[3]) * 4
                             + parseInt(_this.lsPosCaseCore[4]) * 8
                             + parseInt(_this.lsPosCaseCore[5]) * 12
                             + parseInt(_this.lsPosCaseCore[6]) * 24
                             + parseInt(_this.lsPosCaseCore[7]) * 10;

      // リスト上でチェックされたパックから追加分の資源を読み取り
      let creditDayNum = 0;
      let creditWeekNum = 0;
      let creditMonthNum = 0;
      let creditDayCase = 0;
      let creditWeekCase = 0;
      let creditMonthCase = 0;
      let coreDayNum = 0;
      let coreWeekNum = 0;
      let coreMonthNum = 0;
      let coreDayCase = 0;
      let coreWeekCase = 0;
      let coreMonthCase = 0;
      let battleDayNum = 0;
      let battleWeekNum = 0;
      let battleMonthNum = 0;
      let battleDayCase = 0;
      let battleWeekCase = 0;
      let battleMonthCase = 0;
      _this.packs.forEach(function(pack){
        if (pack.check == true) {
          if (pack.division == "デイリー") {
            creditDayCase += pack.items.CaseCredit;
            creditDayNum += pack.items.Credit * 1000;
            coreDayCase += pack.items.CaseCore;
            coreDayNum += pack.items.Core;
            battleDayCase += pack.items.CaseBattle;
            battleDayNum += pack.items.Battle * 1000;
          } else if (pack.division == "ウィークリー") {
            creditWeekCase += pack.items.CaseCredit;
            creditWeekNum += pack.items.Credit * 1000;
            coreWeekCase += pack.items.CaseCore;
            coreWeekNum += pack.items.Core;
            battleWeekCase += pack.items.CaseBattle;
            battleWeekNum += pack.items.Battle * 1000;
          } else if (pack.division == "マンスリー") {
            creditMonthCase += pack.items.CaseCredit;
            creditMonthNum += pack.items.Credit * 1000;
            coreMonthCase += pack.items.CaseCore;
            coreMonthNum += pack.items.Core;
            battleMonthCase += pack.items.CaseBattle;
            battleMonthNum += pack.items.Battle * 1000;
          } else if (pack.name == "30-DAY成長補給品") {
            coreDayCase += 10;
          }
        }
      });

      // 経験値リストから現在レベルの蓄積経験値と目標レベルの蓄積経験値を取得
      var expNow = _this.experience.find(e => e.Lv === _this.coNikkeLv);

      for (let i=0; i <= 2; ++i) {
        if (this.needs[i].NextLv <= this.experience.length) {
          let expNext = this.experience.find(e => e.Lv === this.needs[i].NextLv);
          this.needs[i].NeedCredit = expNext.Credit - expNow.Credit - (this.lsPosCaseCredit[0] * this.coRewardCredit) - (this.lsPosCredit * 1000);
          this.needs[i].NeedBattle = expNext.Battle - expNow.Battle - (this.lsPosCaseBattle[0] * this.coRewardBattle) - (this.lsPosBattle * 1000);
          this.needs[i].NeedCore   = expNext.Core   - expNow.Core   - (this.lsPosCaseCore[0]   * this.coRewardCore)   - this.lsPosCore;
        }
      }

      // クレジットの所要時間（次レベルまでの残り時間を計算）
      let flgCredit = false;
      let flgBattle = false;
      let flgCore = false;
      let lpCnt = -1;
      if (this.needs[0].NextLv <= this.experience.length) lpCnt++; // 次のレベルがデータテーブルの範囲内
      if (this.needs[1].NextLv <= this.experience.length) lpCnt++; // 20レベル区切りの次のレベルがデータテーブルの範囲内
      if (this.needs[2].NextLv <= this.experience.length) lpCnt++; // 20レベル区切りの次の次のレベルがデータテーブルの範囲内

      for (let i = 0; i <= lpCnt; ++i) {
        let nextday = new Date();
        let nextdayStr = "";
        let preCredit = this.needs[i].NeedCredit;
        let preBattle = this.needs[i].NeedBattle;
        let preCore = this.needs[i].NeedCore;

        this.needs[i].HourCredit = 0;
        this.needs[i].HourBattle = 0;
        this.needs[i].HourCore = 0;
        this.needs[i].NeedYen = 0;
        
        this.needs[i].LogCredit = "";
        this.needs[i].LogCredit += "★クレジット";
        this.needs[i].LogCredit += "<br>＜必要量＞";
        this.needs[i].LogCredit += "<br>　Lv" + this.coNikkeLv + "⇒" + this.needs[i].NextLv + "　" + Math.floor((this.needs[i].NeedCredit + (this.lsPosCaseCredit[0] * this.coRewardCredit) + Number(this.lsPosCredit * 1000))/1000).toLocaleString() + "K";
        this.needs[i].LogCredit += "<br>＜収入＞";
        this.needs[i].LogCredit += "<br>　所持　ケース+個別：" + Math.floor(((this.lsPosCaseCredit[0] * this.coRewardCredit) + (this.lsPosCredit * 1000))/1000).toLocaleString() + "K";
        this.needs[i].LogCredit += "<br>　毎日　防御報酬：" + Math.floor(Math.floor(this.coRewardCredit*24)/1000).toLocaleString() + "K";
        this.needs[i].LogCredit += "、殲滅+ミッション：" + Math.floor((Math.floor(this.lsWipeouts * this.coRewardCredit * 2) + (1 * Math.floor(this.coRewardCredit)))/1000).toLocaleString() + "K";
