    mChangeNikkeLv() { // ニケレベル変更
      if (this.coNikkeLv < 1) {
        this.coNikkeLv = 1;
      } else if (this.coNikkeLv > this.experience.length) {
        this.coNikkeLv = this.experience.length;
      } else {
        this.coNikkeLv = Math.floor(this.coNikkeLv);
      }
      localStorage.setItem('coNikkeLv', this.coNikkeLv);
      this.mCalcLeveling();
    },

    mChangeRewardLv() { // 基地防御レベル変更
      if (this.coRewardLv < 1) {
        this.coRewardLv = 1;
      } else if (this.coRewardLv > this.reward.length) {
        this.coRewardLv = this.reward.length;
      } else {
        this.coRewardLv = Math.floor(this.coRewardLv);
      }
      var found = this.reward.find(e => e.Lv === this.coRewardLv);
      this.coRewardCredit = Math.floor(found.Credit*1.6);
      this.coRewardBattle = Math.floor(found.Battle*1.45);
      this.coRewardCore = Math.floor(found.Core*1.45 * Math.pow(10,2)) / Math.pow(10,2);
      localStorage.setItem('coRewardLv', this.coRewardLv);
      localStorage.setItem('coRewardCredit', this.coRewardCredit);
      localStorage.setItem('coRewardBattle', this.coRewardBattle);
      localStorage.setItem('coRewardCore', this.coRewardCore);
      this.mCalcLeveling();
    },

    mChangeWipeouts() { // まとめて殲滅回数変更
      if (this.lsWipeouts < 1) {
        this.lsWipeouts = 1;
      } else if (this.lsWipeouts > 11) {
        this.lsWipeouts = 11;
      } else {
        this.lsWipeouts = Math.floor(this.lsWipeouts);
      }
      localStorage.setItem('lsWipeouts', this.lsWipeouts);
      this.mCalcLeveling();
    },

    mChangePosCaseCredit(idx) { // クレジットケース数量変更
      if (this.lsPosCaseCredit[idx] == "") {
