    mSfCalcBurstGenerate() {  // 部隊編成：バーストゲージ生成量算出
      let _this = this;

      // 部隊1～6まで順に処理
      for (let i = 1; i <= 6; ++i) {
        let generateSummary = [0, 0, 0, 0, 0];

        // 部隊に配置されたニケを取得してバーストゲージ生成量の設定値を抽出
        let squad = document.getElementById("sfSquad"+i);
        squad.childNodes.forEach(function(item){
          let nikke = _this.nikkes.find(e => e.name === item.lang);
          if (nikke != undefined) {
            generateSummary[0] += nikke.generate[0];
            generateSummary[1] += nikke.generate[1];
            generateSummary[2] += nikke.generate[2];
            generateSummary[3] += nikke.generate[3];
            generateSummary[4] += nikke.generate[4];
          };
        });

        // 部隊のバーストゲージ生成スピードを算出
        _this.sfSquadBurstGenerate[i-1].step = 5;
        _this.sfSquadBurstGenerate[i-1].gauge = 0;
        for (let k=0; k<generateSummary.length; ++k) {
          if (generateSummary[k] >= 100) {
            _this.sfSquadBurstGenerate[i-1].step = k;
            _this.sfSquadBurstGenerate[i-1].gauge = generateSummary[k];
            break;
          } else if (generateSummary[k] < 0) {
            _this.sfSquadBurstGenerate[i-1].step = 6;
            _this.sfSquadBurstGenerate[i-1].gauge = 0
            break;
          };
        };
      };
    },

