      //  return;
      //};
      let _this = this;
      if (squadIdx == -1 || _this.sfSquadBuffIdx == squadIdx) {
        _this.sfSquadBuffIdx = 0;
        _this.sfPanelPositon[0] = "1 / 1 / 2 / 2";  // 部隊1～6
        _this.sfPanelPositon[1] = "1 / 2 / 2 / 3";  // 候補一覧
