    mLoadQf(tag) { // 部隊編成：クッキーから部隊欄を読み取り再現する
      let _this = this;
      let buf = "";
      let menbers = [];
      let candidate = document.getElementById("sfCandidate");
      
      _this.sqSquadSelect = tag;
      _this.mSfClearNikke(false);
      
      if (localStorage.getItem('sfSquadList_'+tag+"_1", 1) == null) {
        for (let i = 1; i <= 6; ++i) {
          // 部隊名
          let squadName = localStorage.getItem('sqSquadNamePieces_' + tag + '_' + i, 1);
          if (squadName != null) {
            _this.sqSquadNamePieces[i-1] = squadName;
          } else {
            _this.sqSquadNamePieces[i-1] = "";
          }

          // 部隊キャラ
          buf = localStorage.getItem('sfSquad'+i+"_"+tag, 1);
          let squad = document.getElementById("sfSquad" + i);
          let buf2 = "";
          if (buf) {
            menbers = buf.split(",");
            menbers.forEach(function(member){
              candidate.childNodes.forEach(function(item){
                if (item.lang == member) {
                  item.style.display = "";
                  squad.appendChild(item);
                  buf2 += member + ","
                };
              });
            });
            localStorage.setItem('sfSquad' + i + '_' + tag, buf2);
          };
        };

      } else {
        for (let i = 1; i <= 6; ++i) {
          // 部隊名
          let squadName = localStorage.getItem('sqSquadNamePieces_' + tag + '_' + i, 1);
          if (squadName != null) {
            _this.sqSquadNamePieces[i-1] = squadName;
          } else {
            _this.sqSquadNamePieces[i-1] = "";
          }

          // 部隊キャラ
          buf = localStorage.getItem('sfSquadList_'+tag+"_"+i, 1);
          let squad = document.getElementById("sfSquad" + i);
          if (buf) {
            let orgids = buf.split(",");
            orgids.forEach(function(orgid){
              if (orgid != "") {
                let nikke = _this.nikkes.find(e => e.orgid == orgid.replace("c",""));
                if (!orgid.endsWith("c")) {
                  for (let candiCnt=0; candiCnt<candidate.childNodes.length; ++candiCnt) {
                    let nikkeElement = candidate.childNodes[candiCnt];
                    if (nikkeElement.lang == nikke.name) {
                      nikkeElement.style.display = "";
                      squad.appendChild(nikkeElement);
                      break;
                    };
                  };

                } else {
                  // 使用されていないIDを探す（永久ループ回避で探す範囲を上限1000件とする）
                  let newNikkeId = ""
                  for (let lpCnt=1; lpCnt<=1000; ++lpCnt) {
                    let newNikkeIdBuf = nikke.id + "_copy" + "@".repeat(lpCnt);
                    if (_this.nikkes.find(e => e.id == newNikkeIdBuf) == undefined) {
                      newNikkeId = newNikkeIdBuf;
                      break;
                    };
                  };

                  // ニケ一覧にコピーを追加
                  let newNikke = JSON.parse(JSON.stringify(_this.nikkes.find( d => { return d.orgid == orgid.replace("c",""); })));
                  newNikke.id = newNikkeId;
                  newNikke.emphasis = 0;
                  newNikke.grayout = 0;
                  _this.nikkes.push(newNikke);
                  _this.$set(_this.nikkes, 0, _this.nikkes[0]); // 配列でも画面へ即時反映されるようsetする
                };
              };
            });
          };
        };
      };

      localStorage.setItem('sqSquadSelect', _this.sqSquadSelect);

      // 遅延処理（コピーが反映される前に実行するとエラーが発生するため遅延させる）
      _this.mLoadQf_Delay(tag, 50);
    },

    async mLoadQf_Delay(tag, millisec) { // 部隊編成：クッキーから部隊欄を読み取り再現する
      let _this = this;
      // 指定ミリ秒待機
      await _this.mCoSleepByPromise(millisec);
      // クッキーから部隊欄を読み取り再現
      _this.mLoadQf_After(tag);
    },

    mLoadQf_After(tag) { // 部隊編成：クッキーから部隊欄を読み取り再現する
      let _this = this;
      let candidate = document.getElementById("sfCandidate");

      for (let i = 1; i <= 6; ++i) {
        // 部隊キャラ
        let buf = localStorage.getItem('sfSquadList_'+tag+"_"+i, 1);
        let squad = document.getElementById("sfSquad" + i);
        if (buf) {
          let orgids = buf.split(",");
          orgids.forEach(function(orgid){
            if (orgid.endsWith("c")) {
              // 候補一覧にある該当ニケを探す
              let nikke = _this.nikkes.find(e => e.orgid == orgid.replace("c",""));
              let flgExec = false;
              candidate.childNodes.forEach(function(item){
                if (flgExec == false && item.id.startsWith("sf" + nikke.id + "_copy@")) {
                  item.style.display = "";
                  squad.appendChild(item);
                  flgExec = true;
                };
              });
            };
          });
        };
      };

      _this.mSfCalcBurstGenerate();   // 部隊編成：バースト速度計算
      _this.mSetSquadBuf();           // 部隊バフ一覧セット
    },


    mSfClearNikke(flg) { // 部隊編成：部隊欄から候補一覧へニケを戻す
      let _this = this;
      let ret = true;
      if (flg) {
        ret = window.confirm('部隊の配置をクリアしますが宜しいですか？');
      }

      if (ret) {
        let candidate = document.getElementById("sfCandidate");
        for (let i = 1; i <= 6; ++i) {
          let squad = document.getElementById("sfSquad" + i);
          while (squad.childNodes.length != 0) {
            squad.childNodes.forEach(function(member){
              let idx = 0; // ドロップ先の要素番号
              let cnt = 0;
              // ドロップ先の画像のID＞ドロップする画像のIDとなる画像を探す
              candidate.childNodes.forEach(function(item){
                if(item.id != undefined && item.id.includes("nikke")) {
                  if(item.id <= member.id) idx = cnt+1;
                  cnt++;
                }
              });
              candidate.insertBefore(member, candidate.childNodes.item(idx)); // ドロップ先画像の1つ前に追加
            });
          };
        };
        if (flg) {
          _this.mSaveQf(this.sqSquadSelect);
        }

        // ニケ一覧からコピーを削除
        _this.nikkes = _this.nikkes.filter(function(nikke) { 
          return !nikke.id.includes("_copy@");
        });
      };
    },

    mSmClearNikke(msg) { // 四象限メーカー：グラフから候補一覧へニケを戻す
      let ret = false;
      if (msg != "") {
        ret = window.confirm(msg);
      }

      if (ret) {
        let candidate = document.getElementById("smCandidate");
        let graph = document.getElementById("smGraph");
        let flgFind = true;
        while (flgFind) {
          flgFind = false;
          graph.childNodes.forEach(function(member){
            if ((member.id != undefined) && (member.id.includes("nikke"))) { // idがnullの要素(上下左右の表題)はスキップ
              flgFind = true;
              let idx = 0; // ドロップ先の要素番号
              let cnt = 0;
              // ドロップ先の画像のID＞ドロップする画像のIDとなる画像を探す
              candidate.childNodes.forEach(function(item){
                if(item.id != undefined && item.id.includes("nikke")) {
                  if(item.id <= member.id) idx = cnt+1;
                  cnt++;
                }
              });
              candidate.insertBefore(member, candidate.childNodes.item(idx)); // ドロップ先画像の1つ前に追加

              // ドロップした画像のstyleを元に戻す
              member.style.position = "relative";
              member.style.top = "0px";
              member.style.left = "0px";
              member.style.zIndex = 1;
            };
          });
        };
      };
      return ret;
    },

