    mGetSkillMarkLine(skillText, reg) {
      let spl = skillText.split("<br>");
      let ret = "";
      for (let i=0; i<spl.length; ++i) {
        if (ret != "") ret += "<br>";
        ret += spl[i].replace(reg, '<mark>$1</mark>');
      };
      return ret;
    },

    mGetSkillMarkSentence (skillText, reg) {
      let spl = skillText.split("<br>");
      let ret = "";
      //let record = [];
      let flgFind = false; // スキル全体で検索対象が見つかった場合はtrue
      let flgBound = false; // スキル内に複数の発動条件がある場合にそのうちの1つで検索条件が見つかった場合はtrue

      if (skillText.includes("<mark>")) { // 他の絞り込み条件がヒットしている場合のみ判定（markが含まれていればヒット）
        // スキル文の末尾の行から判定
        for (let i=spl.length-1; i>=0; --i) {
          // 効果の行であり、かつ、絞り込み条件にヒット済みの行である場合
          if (spl[i].includes("・") && spl[i].includes("<mark>")) {
            flgBound = true;
          };

          // 検索条件にヒットする場合は該当箇所を置換
          if (flgBound == true && reg.test(spl[i])) {
            spl[i] = spl[i].replace(reg, '<mark>$1</mark>');
            flgFind = true;
          };

          // スキル文に結合
          ret = spl[i] + ret;
          if (i != 0) {
            ret = "<br>" + ret;
          };
          
          // 現在の行が効果の行ではなく、次の行が効果の行の場合
          if (i != 0 && !spl[i].includes("・") && spl[i-1].includes("・")) {
            flgBound = false;
          };
        };
      };

