    mResetRf() { // 速射ログリセット
      this.timeStart = new Date();
      this.timeLog = "";
      this.rapidTotal = 0;
      this.rapidSuccessPer = 0;
      this.rapidDelay = 0;
      this.rapidDelayPer = 0;
      this.rapidFail = 0;
      this.rapidFailPer = 0;
      this.isRapidDelay = false;
      this.isRapidFail = false;
      this.downSecSuccess = 0; // 成功時Downミリ秒
      this.upSecSuccess = 0; // 成功時upミリ秒
      this.downSecTotal = 0; // 成功時Downミリ秒合計
      this.upSecTotal = 0; // 成功時upミリ秒合計
      this.downSecAvg = 0; // 成功時Downミリ秒平均
      this.upSecAvg = 0; // 成功時upミリ秒平均
    },

    mRtDown() { // 速射ボタンマウスダウン
      let _this = this;
      if(!_this.isDown) {
        _this.isDown = true;
        let timeEnd = new Date();
        let timeDiff = timeEnd.getTime() - _this.timeStart.getTime();
        if (_this.timeLog == "") {
          _this.timeLog = "<br><mark style='background-color: #41d750;'>start</mark>";
        } else if (timeDiff < _this.rfUpSecMin) {
          _this.timeLog = "  <mark style='background-color: #f18960;'>up:" + timeDiff + "ms</mark><br>" + _this.timeLog;
          _this.isRapidFail = true; // 失敗フラグON
        } else if (timeDiff > _this.rfUpSecMax) {
          _this.timeLog = "  <mark>up:" + timeDiff + "ms</mark><br>" + _this.timeLog;
          _this.isRapidDelay = true; // 遅延フラグON
        } else {
          _this.timeLog = "  up:" + timeDiff + "ms<br>" + _this.timeLog;
          _this.upSecSuccess = timeDiff; // 成功時のup時間
        }
        _this.timeStart = timeEnd;
      }
    },

    mRtUp() { // 速射ボタンマウスアップ
      if(this.isDown) {
        this.isDown = false;
        let timeEnd = new Date();
        let timeDiff = timeEnd.getTime() - this.timeStart.getTime();
        if(timeDiff < this.rfDownSecMin) {
          this.timeLog = "<mark style='background-color: #f18960;'>down:" + timeDiff + "ms</mark>" + this.timeLog;
          this.isRapidFail = true; // 失敗フラグON
        } else if(timeDiff > this.rfDownSecMax) {
          this.timeLog = "<mark>down:" + timeDiff + "ms</mark>" + this.timeLog;
          this.isRapidDelay = true; // 遅延フラグON
        } else {
          this.timeLog = "down:" + timeDiff + "ms" + this.timeLog;
          this.downSecSuccess = timeDiff; // 成功時のdown時間
        }
        this.timeStart = timeEnd;
        
        // 回数や各種割合を計算
        this.rapidTotal++; // 回数+1
        if(this.isRapidFail){
          this.rapidFail++; // 失敗数+1
        } else if(this.isRapidDelay) {
          this.rapidDelay++; // 遅延数+1
        } else {
          this.downSecTotal = this.downSecTotal + this.downSecSuccess; // 成功時のdown時間を合計に加算
          this.upSecTotal = this.upSecTotal + this.upSecSuccess; // 成功時のup時間を合計に加算
        }
        this.isRapidDelay = false;
        this.isRapidFail = false;
        this.rapidDelayPer = Math.round(this.rapidDelay / this.rapidTotal * 100);
        this.rapidFailPer = Math.round(this.rapidFail / this.rapidTotal * 100);
        this.rapidSuccessPer = 100 - this.rapidDelayPer - this.rapidFailPer;
        //alert("this.downSecTotal=" + this.downSecTotal);
        //alert("this.this.rapidTotal - this.rapidDelay - this.rapidFail=" + this.rapidTotal - this.rapidDelay - this.rapidFail);
        this.downSecAvg = Math.round(this.downSecTotal / (this.rapidTotal - this.rapidDelay - this.rapidFail));
        this.upSecAvg = Math.round(this.upSecTotal / (this.rapidTotal - this.rapidDelay - this.rapidFail));
      }
    },

