  computed: {
    packs_sort() { // 課金パック一覧の絞り込みとソート
      var _this = this; // forEach内のthisは配列を指してしまうのでthisを別名にしておく

      // ソート
      if(this.sort_key1 != "") {
        let set = 1;
        this.sort_asc ? (set = 1) : (set = -1)
        this.packs.sort((a, b) => {
          //if (a[this.sort_key2] > b[this.sort_key2]) return -1;
          //if (a[this.sort_key2] < b[this.sort_key2]) return 1;
          if (a[this.sort_key1] < b[this.sort_key1]) return -1 * set;
          if (a[this.sort_key1] > b[this.sort_key1]) return 1 * set;
          return 0;
        })
      }

      // 絞り込み
      var data = _this.packs;

      //表示対象区分
      let flgDivAll = true;
      _this.divisions.forEach(function(division){
        if(division.check){
          flgDivAll = false;
        }
      })
      if(!flgDivAll) {
        _this.divisions.forEach(function(division){
          if(!division.check){
            data = data.filter(function (row) {
              return row['division'].indexOf(division.name) == -1;
            });
          }
        })
      }

      //入力した条件で絞り込み
      let flgConAll = true;
      _this.contents.forEach(function(content){
        if(content.check){
          flgConAll = false;
        }
      })
      if(!flgConAll) {
        data = data.filter(function (row) {
          let flgFing = false;
          _this.contents.forEach(function(content){
            if(content.check){
              if(row['content'].indexOf(content.name) >= 0) {
                flgFing = true;
              };
            };
          });
          return flgFing;
        });
      }

      //ハイライト設定
      let reg1 = new RegExp("<mark style='background-color: #f7f463;'>",'g');
      let reg2 = new RegExp("<mark style='background-color: #f18960;'>",'g');
      let reg3 = new RegExp("<mark style='background-color: #86ff40;'>",'g');
      let reg4 = new RegExp("<mark style='background-color: #659bff;'>",'g');
      let reg5 = new RegExp("<mark style='background-color: #f742c9;'>",'g');
      let regE = new RegExp("</mark>",'g');
      let num = 1;
      _this.packs.forEach(function(pack){
        pack.content = pack.content.replace(reg1, "");
        pack.content = pack.content.replace(reg2, "");
        pack.content = pack.content.replace(reg3, "");
        pack.content = pack.content.replace(reg4, "");
        pack.content = pack.content.replace(reg5, "");
        pack.content = pack.content.replace(regE, "");
      })
      _this.contents.forEach(function(content){
        if (content.check) {
          let reg3 = new RegExp(content.name,'g');
          _this.packs.forEach(function(pack){
            
            switch(num){
              case 1:
                pack.content = pack.content.replace(reg3, "<mark style='background-color: #f7f463;'>" + content.name + "</mark>");
                break;
              case 2:
                pack.content = pack.content.replace(reg3, "<mark style='background-color: #f18960;'>" + content.name + "</mark>");
                break;
              case 3:
                pack.content = pack.content.replace(reg3, "<mark style='background-color: #86ff40;'>" + content.name + "</mark>");
                break;
              case 4:
                pack.content = pack.content.replace(reg3, "<mark style='background-color: #659bff;'>" + content.name + "</mark>");
                break;
              default:
                pack.content = pack.content.replace(reg3, "<mark style='background-color: #f742c9;'>" + content.name + "</mark>");
            }
          })
          if(++num > 5){
            num = 1;
          }
        }
      })

      return data
    },

    talks_sort() { // 面談一覧の絞り込みとソート
      let _this = this; // forEach内のthisは配列を指してしまうのでthisを別名にしておく
      let data = _this.talks;
      let keywrod = [1];
      let forceCheck = false;
      
      keywrod[0] = _this.tsSearchWord1.trim();
      //keywrod[1] = _this.tsSearchWord2.trim();
      keywrod[1] = _this.tsSearchWord1s.trim();
      //keywrod[3] = _this.tsSearchWord2s.trim();
      
      // 検索ワードにぁぃぅぇぉ等を入力された場合は平仮名とのマッチングができるよう置換
      let keywrodHira = keywrod[0];
      keywrodHira = keywrodHira.replace(/ぁ/g, 'あ');
      keywrodHira = keywrodHira.replace(/ぃ/g, 'い');
      keywrodHira = keywrodHira.replace(/ぅ/g, 'う');
      keywrodHira = keywrodHira.replace(/ぇ/g, 'え');
      keywrodHira = keywrodHira.replace(/ぉ/g, 'お');
      keywrodHira = keywrodHira.replace(/ゃ/g, 'や');
      keywrodHira = keywrodHira.replace(/ゅ/g, 'ゆ');
      keywrodHira = keywrodHira.replace(/ょ/g, 'よ');
      keywrodHira = keywrodHira.replace(/ゎ/g, 'わ');

      for(let i=0; i<=1; ++i) {
        keywrod[i] = keywrod[i].replace(/!/g, '！');
        keywrod[i] = keywrod[i].replace(/\?/g, '？');
        keywrod[i] = keywrod[i].replace(/１/g, '1');
        keywrod[i] = keywrod[i].replace(/２/g, '2');
        keywrod[i] = keywrod[i].replace(/３/g, '3');
        keywrod[i] = keywrod[i].replace(/４/g, '4');
        keywrod[i] = keywrod[i].replace(/５/g, '5');
        keywrod[i] = keywrod[i].replace(/６/g, '6');
        keywrod[i] = keywrod[i].replace(/７/g, '7');
        keywrod[i] = keywrod[i].replace(/８/g, '8');
        keywrod[i] = keywrod[i].replace(/９/g, '9');
        keywrod[i] = keywrod[i].replace(/０/g, '0');
      };

      // チェックしたニケが誰もいない場合は全員チェックされている扱いとする
      if (!_this.tsTalkNikkes.some(item => item.check === true)) forceCheck = true;

      // 画像認識Onの場合はあいまい検索を行う
      let hitMax = 0;
      let hit;
      if(_this.tsImageManu == 1 || _this.tsImageAuto == 1) {
        let cmp = [1];
        cmp[0] = _this.trigramify(keywrod[0]);
        cmp[1] = _this.trigramify(keywrod[1]);
        //cmp[2] = _this.trigramify(keywrod[2]);
        //cmp[3] = _this.trigramify(keywrod[3]);
        data.forEach(function(nikke) {
          _this.tsTalkNikkes.forEach(function(target){
            if((target.name == nikke.name && target.check) || forceCheck) { // 面談候補でチェックされているニケである、または面談候補が全てチェックされておらず全員対象扱いになっている
              nikke.hit = 0;
              //nikke.cases[1].hit = 0;

              hit = _this.relevance(nikke.trigramify, cmp[0]); // 上選択肢を比較
              if(hit > nikke.hit) {
                nikke.hit = hit;
              };
              if(nikke.hit > hitMax) {
                hitMax = nikke.hit;
              };
              
              hit = _this.relevance(nikke.trigramify, cmp[1]); // 上選択肢を比較
              if(hit > nikke.hit) {
                nikke.hit = hit;
              };
              if(nikke.hit > hitMax) {
                hitMax = nikke.hit;
              };
              
              /*hit = _this.relevance(nikke.cases[1].trigramify, cmp[1]); // 下選択肢を比較(補正後画像)
              if(hit > nikke.cases[1].hit) {
                nikke.cases[1].hit = hit;
              };;
              if(nikke.cases[1].hit > hitMax) {
                hitMax = nikke.cases[1].hit;
              };

              hit = _this.relevance(nikke.cases[1].trigramify, cmp[3]); // 下選択肢を比較(補正後画像)
              if(hit > nikke.cases[1].hit) {
                nikke.cases[1].hit = hit;
              };
              if(nikke.cases[1].hit > hitMax) {
                hitMax = nikke.cases[1].hit;
              };*/
            };
          });
        });
      };

      if(hitMax < 0.2 && _this.tsSearchWordCls == 1) {
        // 画像認識の場合でヒット率が低すぎる場合は更新しない
        data = data.filter(function (nikke) {
          return nikke.disp; // 前回保存していた表示・非表示の値を設定しなおす
        });
      } else {
        data = data.filter(function (nikke) {
          let flgFing = false;
          nikke.disp = false;
          if(keywrod[0] != "") {
            _this.tsTalkNikkes.forEach(function(target){
              if((target.name == nikke.name && target.check) || forceCheck) { // 面談候補でチェックされているニケである、または面談候補が全てチェックされておらず全員対象扱いになっている
                //nikke.cases.forEach(function(caseItem){ //選択肢1～2
                  //if(_this.tsSearchType == "部分一致") {
                    if(keywrod[0] == "*") {
                      nikke.disp = true;
                      flgFing = true;
                    } else if(nikke.select.indexOf(keywrod[0]) >= 0) {
                      nikke.disp = true;
                      flgFing = true;
                    } else if(_this.tsHiragana && nikke.hiragana.indexOf(keywrodHira) >= 0) {
                      nikke.disp = true;
                      flgFing = true;
                    } else if(_this.tsImageManu == 1 || _this.tsImageAuto == 1) {
                      if(hitMax >= 0.2 && nikke.hit >= (hitMax - 0.1)) {
                        nikke.disp = true;
                        flgFing = true;
                        _this.tsCaptureSkipSec = 2;
                      };
                    };
                  //} else {
                  //  if(caseItem.select.startsWith(keywrod[0])) {
                  //    nikke.disp = true;
                  //    flgFing = true;
                  //  } else if(_this.tsHiragana && caseItem.hiragana.startsWith(keywrodHira)) {
                  //    nikke.disp = true;
                  //    flgFing = true;
                  //  } else if(_this.tsImageManu == 1 || _this.tsImageAuto) {
                  //    if(hitMax >= 0.3 && caseItem.hit >= (hitMax - 0.1)) {
                  //      nikke.disp = true;
                  //      flgFing = true;
                  //      _this.tsCaptureSkipSec = 3;
                  //    };
                  //  };
                  //};
                //});            
              };
            });
          };
          return flgFing;
        });
      };

      return data
    }
  },

  destroyed: function () { // PT作成支援関連
    window.removeEventListener('dragstart', function(e){}, false)
    window.removeEventListener('drag', function(e){}, false)
    window.removeEventListener('dragover', function(e){}, false)
    window.removeEventListener('drop', function(e){}, false)
    //clearInterval(this.updateMessageTimer)
  }

}
</script>


